import React, { useState, useEffect } from 'react';
import { AlarmClock } from './components/AlarmClock';
import { TaskFlow } from './components/TaskFlow';
import { AlarmConfig, Persona, TaskType } from './types';
import { generateMotivationalQuote } from './services/geminiService';
import { Volume2, VolumeX } from 'lucide-react';

export default function App() {
  const [persona, setPersona] = useState<Persona>(Persona.STUDENT);
  const [config, setConfig] = useState<AlarmConfig>({
    time: "07:00",
    enabled: false,
    tasks: [TaskType.PUZZLE, TaskType.PHOTO_FACE],
    snoozeAllowed: false
  });

  const [isAlarmRinging, setIsAlarmRinging] = useState(false);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [oscillator, setOscillator] = useState<OscillatorNode | null>(null);
  const [quote, setQuote] = useState<string>("");

  // Sound Logic
  const startAlarmSound = () => {
    try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(440, ctx.currentTime);
        // Annoying pulse
        osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

        gain.gain.value = 0.1;

        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();

        setAudioContext(ctx);
        setOscillator(osc);

        // Pulse interval
        const interval = setInterval(() => {
            if(osc.frequency) {
               osc.frequency.setValueAtTime(440, ctx.currentTime); 
               osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);
            }
        }, 1000);
        (osc as any).interval = interval;

    } catch (e) {
        console.error("Audio error", e);
    }
  };

  const stopAlarmSound = () => {
    if (oscillator) {
        clearInterval((oscillator as any).interval);
        oscillator.stop();
        oscillator.disconnect();
    }
    if (audioContext) {
        audioContext.close();
    }
    setOscillator(null);
    setAudioContext(null);
  };

  const handleTriggerAlarm = async () => {
    setIsAlarmRinging(true);
    startAlarmSound();
    const q = await generateMotivationalQuote(persona);
    setQuote(q);
  };

  const handleTasksComplete = () => {
    setIsAlarmRinging(false);
    stopAlarmSound();
    setConfig(prev => ({ ...prev, enabled: false })); // Disable alarm after success
  };

  // If alarm is ringing but user refreshes or closes, we lose state. 
  // In a real PWA, we'd use local storage and Service Workers.
  // For this demo, simple state is enough.

  return (
    <div className="min-h-screen w-full bg-zinc-950 text-zinc-100 flex flex-col relative overflow-hidden">
        {/* Background Gradients */}
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/20 rounded-full blur-[100px] pointer-events-none" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/20 rounded-full blur-[100px] pointer-events-none" />

        {isAlarmRinging ? (
            <div className="z-10 flex flex-col items-center justify-center min-h-screen">
                <div className="absolute top-6 animate-pulse text-red-500 font-black tracking-widest text-2xl flex items-center gap-2">
                    <Volume2 className="w-8 h-8" />
                    ALARM ACTIVE
                    <Volume2 className="w-8 h-8" />
                </div>

                {/* Intro/Motivational Quote before tasks */}
                <div className="mb-8 px-8 text-center max-w-lg">
                     <p className="text-2xl font-bold text-white mb-2">Rise and Shine, {persona}!</p>
                     <p className="text-zinc-400 italic">"{quote}"</p>
                </div>

                <TaskFlow 
                    persona={persona}
                    tasks={config.tasks}
                    onComplete={handleTasksComplete}
                />
            </div>
        ) : (
            <AlarmClock 
                config={config}
                persona={persona}
                onUpdateConfig={setConfig}
                onUpdatePersona={setPersona}
                onTriggerAlarm={handleTriggerAlarm}
            />
        )}
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { Persona } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// gemini-3-flash-preview supports text, images, and audio.
const MODEL_NAME = 'gemini-3-flash-preview';

export const generatePuzzleForPersona = async (persona: Persona): Promise<{ question: string; options: string[]; correctIndex: number }> => {
  try {
    const prompt = `Generate a multiple-choice question suitable for a "${persona}" to prove they are awake. 
    For a Student: Math or Logic.
    For UPSC: General Knowledge or History.
    For Gym Freak: Nutrition or Anatomy.
    For CEO: Business logic or Leadership situational.
    For School Kid: Simple Math or Animal trivia.
    For Night-shift: Alertness check.

    Return ONLY JSON.`;

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING } },
            correctIndex: { type: Type.INTEGER, description: "Index of the correct option (0-3)" }
          },
          required: ["question", "options", "correctIndex"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");
    return JSON.parse(text);
  } catch (error) {
    console.error("Gemini Puzzle Error:", error);
    return {
      question: "What is 2 + 2?",
      options: ["3", "4", "5", "6"],
      correctIndex: 1
    };
  }
};

export const generateMotivationalQuote = async (persona: Persona): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: `Give a short, punchy, wake-up call (1 sentence) for a ${persona}. Be strict but encouraging.`
    });
    return response.text || "Wake up! Time to conquer the world.";
  } catch (e) {
    return "Wake up! You got this.";
  }
};

export const verifyAwakeFace = async (imageBase64: string): Promise<{ passed: boolean; message: string }> => {
  try {
    const prompt = "Analyze this selfie. Does the person look awake with their eyes open? If yes, return true. If they look asleep, drowsy, or eyes are closed, return false. Provide a very short reason.";

    // Extract mime type dynamically
    const mimeMatch = imageBase64.match(/^data:(image\/[a-zA-Z+]+);base64,/);
    const mimeType = mimeMatch ? mimeMatch[1] : "image/jpeg";
    const data = imageBase64.replace(/^data:image\/[a-zA-Z+]+;base64,/, "");

    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: {
        parts: [
          { inlineData: { mimeType, data } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            passed: { type: Type.BOOLEAN },
            message: { type: Type.STRING }
          }
        }
      }
    });

    const result = JSON.parse(response.text || "{}");
    return {
      passed: result.passed ?? false,
      message: result.message || "Could not verify face."
    };
  } catch (error) {
    console.error("Face Check Error:", error);
    return { passed: false, message: "Error analyzing photo. Try again with better lighting." };
  }
};

