  UPSC_ASPIRANT = 'Competitive Exam Aspirant',
  GYM_FREAK = 'Gym Discipline',
  PROFESSIONAL = 'Professional',
  NIGHT_SHIFT = 'Night Shift Worker'
}

export enum DisciplineLevel {
  MERCY = 'Mercy',   // Easy escape
  NORMAL = 'Normal', // Balanced
  BRUTAL = 'Brutal'  // No shortcuts
}

export enum AlarmPurpose {
  CLASS = 'Class',
  STUDY = 'Study',
  WORKOUT = 'Workout',
  MEETING = 'Meeting',
  HABIT = 'Habit'
}

export enum TaskType {
  PUZZLE = 'PUZZLE',
  PHOTO_FACE = 'PHOTO_FACE',
  READ_SENTENCE = 'READ_SENTENCE',
  WALK_STEPS = 'WALK_STEPS',
  SCAN_QR = 'SCAN_QR',
  HOLD_BUTTON = 'HOLD_BUTTON',
  BREATHING = 'BREATHING'
}

export interface UserProfile {
  persona: Persona;
  discipline: DisciplineLevel;
  onboarded: boolean;
  wakeScore: number;
  streak: number;
}

export interface AlarmConfig {
  time: string; // HH:mm
