export interface WakeTask {
  type: TaskType;
  description: string;
  meta?: any; // For holding specific parameters like step count or puzzle difficulty
}

import { Persona, DisciplineLevel, TaskType, WakeTask } from '../types';

export const generateWakeChain = (persona: Persona, discipline: DisciplineLevel): WakeTask[] => {
  const chain: WakeTask[] = [];

  // 1. Cognitive Activation (Puzzle)
  let puzzleDiff = 'Easy';
  if (discipline === DisciplineLevel.NORMAL) puzzleDiff = 'Medium';
  if (discipline === DisciplineLevel.BRUTAL) puzzleDiff = 'Hard';

  chain.push({
    type: TaskType.PUZZLE,
    description: `Solve ${puzzleDiff} ${persona === Persona.STUDENT ? 'Math' : 'Logic'} Puzzle`,
    meta: { difficulty: puzzleDiff }
  });

  // 2. Physical/Biometric Activation based on Persona
  if (persona === Persona.GYM_FREAK) {
    chain.push({
      type: TaskType.WALK_STEPS,
      description: discipline === DisciplineLevel.BRUTAL ? "Sprint 50 Steps" : "Walk 20 Steps",
      meta: { target: discipline === DisciplineLevel.BRUTAL ? 50 : 20 }
    });
  } else if (persona === Persona.UPSC_ASPIRANT) {
    chain.push({
      type: TaskType.READ_SENTENCE,
      description: "Read Daily Affirmation Loudly"
    });
  } else if (persona === Persona.NIGHT_SHIFT) {
    chain.push({
      type: TaskType.PHOTO_FACE,
      description: "Light Exposure Face Check"
    });
  } else {
    // Default physical check
    if (discipline !== DisciplineLevel.MERCY) {
       chain.push({
         type: TaskType.PHOTO_FACE,
         description: "Verify Awake Face"
       });
    }
  }

  // 3. Brutal Mode Extras
  if (discipline === DisciplineLevel.BRUTAL) {
    chain.push({
      type: TaskType.SCAN_QR,
      description: "Scan Bathroom QR Code / Object"
    });
    chain.push({
      type: TaskType.HOLD_BUTTON,
      description: "Hold 'I Am Awake' for 20s"
    });
  }

  // 4. Verification Finalizer (All modes except Mercy)
  if (discipline !== DisciplineLevel.MERCY) {
      chain.push({
          type: TaskType.READ_SENTENCE,
          description: "Final Voice Confirmation"
      });
  }

  return chain;
};

