export const WakeLockScreen: React.FC<WakeLockScreenProps> = ({ profile, alarmConfig, onSuccess, onFailure }) => {
  const [tasks, setTasks] = useState<WakeTask[]>([]);
  const [chainGenerated, setChainGenerated] = useState(false);
  const [quote, setQuote] = useState("");
  const [finalCheckVisible, setFinalCheckVisible] = useState(false);

  // Audio state
  const [audioCtx, setAudioCtx] = useState<AudioContext | null>(null);
  const [oscillator, setOscillator] = useState<OscillatorNode | null>(null);
  const [volume, setVolume] = useState(0.1);

  // Initialize Wake Chain
  useEffect(() => {
    if (!chainGenerated) {
        const chain = generateWakeChain(profile.persona, profile.discipline);
        setTasks(chain);

        generateMotivationalQuote(profile.persona).then(setQuote);
        setChainGenerated(true);

        // Start Sound
        startAlarmSound();
    }
  }, [chainGenerated, profile]);

  // Volume escalation
  useEffect(() => {
    const interval = setInterval(() => {
       setVolume(v => Math.min(v + 0.05, 1.0));
    }, 10000); // Increase every 10s
    return () => clearInterval(interval);
  }, []);

  // Update gain node if volume changes
  useEffect(() => {
    if (audioCtx && oscillator) {
        // In a real app we'd update the gain node here.
        // For this demo, we assume the sound function handles it or we restart.
    }
  }, [volume]);

  const startAlarmSound = () => {
    try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sawtooth';
        // Alternating siren freq
        osc.frequency.setValueAtTime(600, ctx.currentTime);
        osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.2);

        gain.gain.value = volume;

        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();

        setAudioCtx(ctx);
        setOscillator(osc);

        // Siren loop
        const loop = setInterval(() => {
            if (osc.frequency) {
                osc.frequency.setValueAtTime(600, ctx.currentTime);
                osc.frequency.exponentialRampToValueAtTime(1200, ctx.currentTime + 0.2);
            }
        }, 500);
        (osc as any).loop = loop;

    } catch (e) {
        console.error("Audio init failed", e);
    }
  };

  const stopAlarm = () => {
    if (oscillator) {
        clearInterval((oscillator as any).loop);
        oscillator.stop();
        oscillator.disconnect();
    }
    if (audioCtx) {
        audioCtx.close();
    }
  };

  const handleTasksComplete = () => {
    stopAlarm();
    setFinalCheckVisible(true);
    // Auto-fail if they don't confirm in 60s
    setTimeout(() => {
        if(finalCheckVisible) {
             // Restart alarm logic would go here
             startAlarmSound(); // Punish
        }
    }, 60000);
  };

  if (finalCheckVisible) {
      return (
          <div className="fixed inset-0 bg-black z-50 flex flex-col items-center justify-center p-8 text-center animate-fade-in">
              <ShieldAlert className="w-20 h-20 text-yellow-500 mb-6 animate-pulse" />
              <h1 className="text-3xl font-bold text-white mb-4">VERIFICATION PHASE</h1>
              <p className="text-zinc-400 mb-12">Wait 10 seconds to confirm you are truly awake.</p>

              <button 
                onClick={onSuccess}
                className="w-full py-6 bg-green-500 hover:bg-green-600 text-black font-black text-xl rounded-2xl shadow-lg shadow-green-500/20"
              >
                  I AM AWAKE & CONSCIOUS
              </button>
          </div>
      );
  }

  return (
    <div className="fixed inset-0 bg-red-950/20 z-50 flex flex-col backdrop-blur-3xl">
        <div className="absolute inset-0 bg-gradient-to-b from-black via-zinc-900 to-red-900/50" />

        <div className="relative z-10 flex-1 flex flex-col items-center p-6">
            <div className="w-full flex justify-between items-center mb-8">
                <div className="flex items-center gap-2 text-red-500 font-bold animate-pulse">
                    <Lock className="w-5 h-5" /> WAKE LOCK ACTIVE
                </div>
                <div className="text-xs text-zinc-500 uppercase">
                    Vol: {Math.round(volume * 100)}%
                </div>
            </div>

            <div className="text-center mb-6">
                <h2 className="text-4xl font-black text-white italic tracking-tighter mb-2">WAKE UP, {profile.persona.toUpperCase()}</h2>
                <p className="text-red-200/80 font-serif text-lg">"{quote}"</p>
            </div>

            <div className="w-full max-w-md flex-1 bg-zinc-950/80 border border-zinc-800 rounded-3xl overflow-hidden shadow-2xl">
                {tasks.length > 0 && (
                    <TaskFlow 
                        persona={profile.persona} 
                        tasks={tasks.map(t => t.type)} 
                        onComplete={handleTasksComplete} 
                    />
                )}
            </div>

            <p className="mt-6 text-zinc-500 text-xs text-center max-w-xs">
                Do not close the app. Failure to complete tasks will result in penalty.
            </p>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Onboarding } from './components/Onboarding';
import { Dashboard } from './components/Dashboard';
import { WakeLockScreen } from './components/WakeLockScreen';
import { UserProfile, AlarmConfig, AlarmPurpose, Persona, DisciplineLevel } from './types';

// Storage Keys
const PROFILE_KEY = 'wake_enforcer_profile';
const ALARM_KEY = 'wake_enforcer_alarm';

export default function App() {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [alarmConfig, setAlarmConfig] = useState<AlarmConfig>({
    time: "07:00",
    purpose: AlarmPurpose.WORKOUT,
    active: false
  });
  const [isAlarmActive, setIsAlarmActive] = useState(false);

  // Load Persisted Data
  useEffect(() => {
    const savedProfile = localStorage.getItem(PROFILE_KEY);
    if (savedProfile) {
        setProfile(JSON.parse(savedProfile));
    }

    const savedAlarm = localStorage.getItem(ALARM_KEY);
    if (savedAlarm) {
        setAlarmConfig(JSON.parse(savedAlarm));
    }
  }, []);

  // Alarm Checker
  useEffect(() => {
    const checkAlarm = setInterval(() => {
        if (alarmConfig.active && !isAlarmActive) {
            const now = new Date();
            const [h, m] = alarmConfig.time.split(':').map(Number);
            if (now.getHours() === h && now.getMinutes() === m && now.getSeconds() === 0) {
                triggerAlarm();
            }
        }
    }, 1000);
    return () => clearInterval(checkAlarm);
  }, [alarmConfig, isAlarmActive]);

  const saveProfile = (p: UserProfile) => {
    setProfile(p);
    localStorage.setItem(PROFILE_KEY, JSON.stringify(p));
  };

  const saveAlarm = (c: AlarmConfig) => {
    setAlarmConfig(c);
    localStorage.setItem(ALARM_KEY, JSON.stringify(c));
  };

  const triggerAlarm = () => {
    setIsAlarmActive(true);
    // Attempt wake lock
    if ('wakeLock' in navigator) {
        (navigator as any).wakeLock.request('screen').catch(console.error);
    }
  };

  const handleWakeSuccess = () => {
    setIsAlarmActive(false);
    saveAlarm({ ...alarmConfig, active: false });
    if (profile) {
        saveProfile({ 
            ...profile, 
            wakeScore: Math.min(profile.wakeScore + 5, 100),
            streak: profile.streak + 1 
        });
    }
  };

  const handleWakeFailure = () => {
    // Penalty logic
    setIsAlarmActive(false); // Or force restart
    saveAlarm({ ...alarmConfig, active: false });
    if (profile) {
        saveProfile({
            ...profile,
            wakeScore: Math.max(profile.wakeScore - 10, 0),
            streak: 0
        });
    }
  };

  const resetProfile = () => {
    localStorage.removeItem(PROFILE_KEY);
    setProfile(null);
  };

  if (!profile) {
    return <Onboarding onComplete={saveProfile} />;
  }

  return (
    <div className="bg-zinc-950 min-h-screen text-white font-sans selection:bg-indigo-500/30">
        {isAlarmActive ? (
            <WakeLockScreen 
                profile={profile}
                alarmConfig={alarmConfig}
                onSuccess={handleWakeSuccess}
                onFailure={handleWakeFailure}
            />
        ) : (
            <Dashboard 
                profile={profile}
                alarmConfig={alarmConfig}
                onSetAlarm={saveAlarm}
                onActivate={() => saveAlarm({...alarmConfig, active: true})}
                onResetProfile={resetProfile}
            />
        )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Persona, AlarmConfig, TaskType } from '../types';
import { Bell, Play, Square, Moon, Briefcase, Dumbbell, GraduationCap, User, BookOpen } from 'lucide-react';

interface AlarmClockProps {
  config: AlarmConfig;
  persona: Persona;
  onUpdateConfig: (config: AlarmConfig) => void;
  onUpdatePersona: (persona: Persona) => void;
  onTriggerAlarm: () => void;
}

export const AlarmClock: React.FC<AlarmClockProps> = ({ config, persona, onUpdateConfig, onUpdatePersona, onTriggerAlarm }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      if (config.enabled) {
        const [alarmHour, alarmMinute] = config.time.split(':').map(Number);
        if (now.getHours() === alarmHour && now.getMinutes() === alarmMinute && now.getSeconds() === 0) {
          onTriggerAlarm();
        }
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [config, onTriggerAlarm]);

  const toggleTask = (task: TaskType) => {
    const newTasks = config.tasks.includes(task)
      ? config.tasks.filter(t => t !== task)
      : [...config.tasks, task];
    onUpdateConfig({ ...config, tasks: newTasks });
  };

  const getPersonaIcon = (p: Persona) => {
    switch(p) {
        case Persona.STUDENT: return <BookOpen className="w-5 h-5" />;
        case Persona.PROFESSIONAL: return <Briefcase className="w-5 h-5" />;
        case Persona.GYM_FREAK: return <Dumbbell className="w-5 h-5" />;
        case Persona.UPSC_ASPIRANT: return <GraduationCap className="w-5 h-5" />;
        case Persona.NIGHT_SHIFT: return <Moon className="w-5 h-5" />;
        default: return <User className="w-5 h-5" />;
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 space-y-8 max-w-md mx-auto w-full">
      <div className="text-center space-y-2">
        <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400 drop-shadow-lg">
          {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </h1>
        <p className="text-zinc-500 font-medium">{currentTime.toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric'})}</p>
      </div>

      <div className="w-full bg-zinc-900/50 p-6 rounded-3xl border border-zinc-800 shadow-xl backdrop-blur-sm">
        {/* Persona Selector */}
        <div className="mb-6">
          <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Identity Mode</label>
          <div className="grid grid-cols-2 gap-2">
            {Object.values(Persona).map((p) => (
              <button
                key={p}
                onClick={() => onUpdatePersona(p)}
                className={`flex items-center gap-2 p-3 rounded-xl text-sm transition-all duration-200 ${
                  persona === p 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' 
                  : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'
                }`}
              >
                {getPersonaIcon(p)}
                <span className="truncate">{p}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Alarm Time */}
        <div className="mb-6">
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Wake Up Time</label>
            <div className="flex items-center gap-4 bg-zinc-950 p-4 rounded-2xl border border-zinc-800">
                <input 
                    type="time" 
                    value={config.time}
                    onChange={(e) => onUpdateConfig({...config, time: e.target.value})}
                    className="bg-transparent text-3xl font-bold text-white focus:outline-none w-full"
                />
                <button 
                    onClick={() => onUpdateConfig({...config, enabled: !config.enabled})}
                    className={`p-3 rounded-full transition-all ${config.enabled ? 'bg-green-500 text-black' : 'bg-zinc-800 text-zinc-500'}`}
                >
                    <Bell className="w-6 h-6" fill={config.enabled ? "currentColor" : "none"} />
                </button>
            </div>
        </div>

        {/* Tasks */}
        <div>
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Required Challenges</label>
            <div className="space-y-2">
                {[
                    { type: TaskType.PUZZLE, label: 'Mind Puzzle' },
                    { type: TaskType.PHOTO_FACE, label: 'Verify Awake Face' },
                    { type: TaskType.READ_SENTENCE, label: 'Loud Reading' },
                    { type: TaskType.WALK_STEPS, label: 'Walk 20 Steps' },
                    { type: TaskType.SCAN_QR, label: 'Bathroom Scan' },
                ].map((task) => (
                    <button
                        key={task.type}
                        onClick={() => toggleTask(task.type)}
                        className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${
                            config.tasks.includes(task.type)
                            ? 'border-indigo-500/50 bg-indigo-500/10 text-indigo-200'
                            : 'border-zinc-800 bg-zinc-900 text-zinc-500 hover:border-zinc-700'
                        }`}
                    >
                        <span className="font-medium">{task.label}</span>
                        <div className={`w-5 h-5 rounded-md border flex items-center justify-center ${config.tasks.includes(task.type) ? 'bg-indigo-500 border-indigo-500' : 'border-zinc-600'}`}>
