import React, { useState, useEffect, useRef } from 'react';
import { Persona, TaskType } from '../types';
import { verifyChanting, verifyAwakeFace, verifySpeech, getTongueTwister, verifyQRCodeOrObject } from '../services/geminiService';
import { Loader2, Camera, Mic, Activity, XCircle, Zap } from 'lucide-react';

interface TaskFlowProps {
  persona: Persona;
  tasks: TaskType[];
  onComplete: () => void;
}

export const TaskFlow: React.FC<TaskFlowProps> = ({ persona, tasks, onComplete }) => {
  const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Photo/QR State
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  // Reading State
  const [sentence, setSentence] = useState<string>("");
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Chanting State
  const [chantCount, setChantCount] = useState(0);
  const TARGET_CHANTS = 108;
  const analyserRef = useRef<AnalyserNode | null>(null);
  const chantAudioContextRef = useRef<AudioContext | null>(null);
  const lastChantTimeRef = useRef<number>(0);
  const isChantingRef = useRef(false);

  // Steps State
  const [steps, setSteps] = useState(0);
  const targetSteps = 20;

  const currentTask = tasks[currentTaskIndex];

  // Initialize Task Logic
  useEffect(() => {
    if (!currentTask) {
        onComplete();
        return;
    }

    const initTask = async () => {
      setLoading(true);
      setError(null);
      setCapturedImage(null);
      setIsRecording(false);
      setChantCount(0);
      cleanupChantAudio();

      if (currentTask === TaskType.READ_SENTENCE) {
        const s = await getTongueTwister();
        setSentence(s);
      } else if (currentTask === TaskType.WALK_STEPS) {
        setSteps(0);
      }
      setLoading(false);
    };

    initTask();

    return () => {
      cleanupChantAudio();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTaskIndex, currentTask]);

  const handleNext = () => {
    cleanupChantAudio();
    if (currentTaskIndex + 1 >= tasks.length) {
      onComplete();
    } else {
      setCurrentTaskIndex(prev => prev + 1);
    }
  };

  // --- Chanting Logic ---

  const cleanupChantAudio = () => {
    if (chantAudioContextRef.current) {
        chantAudioContextRef.current.close();
        chantAudioContextRef.current = null;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    isChantingRef.current = false;
  };

  const startChantingSession = async () => {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        // Setup Media Recorder for Verification
        const mediaRecorder = new MediaRecorder(stream);
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (e) => {
            audioChunksRef.current.push(e.data);
        };

        mediaRecorder.start();

        // Setup Audio Analysis for Counting
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        chantAudioContextRef.current = ctx;
        const source = ctx.createMediaStreamSource(stream);
        const analyser = ctx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        setIsRecording(true);
        isChantingRef.current = true;

        requestAnimationFrame(detectChantPeak);

    } catch (err) {
        setError("Microphone required for chanting.");
    }
  };

  const detectChantPeak = () => {
    if (!isChantingRef.current || !analyserRef.current) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(dataArray);

    // Calculate Average Volume
    let sum = 0;
    for (let i = 0; i < bufferLength; i++) {
        sum += dataArray[i];
    }
    const average = sum / bufferLength;

    // Threshold logic
    const now = Date.now();
    // If volume > 30 and enough time passed since last chant (e.g., 800ms)
    if (average > 30 && (now - lastChantTimeRef.current > 800)) {
        lastChantTimeRef.current = now;
        setChantCount(prev => {
            const newCount = prev + 1;
            if (newCount >= TARGET_CHANTS) {
                finishChanting();
                return TARGET_CHANTS;
            }
            return newCount;
        });
    }

    if (isChantingRef.current) {
        requestAnimationFrame(detectChantPeak);
    }
  };

  const finishChanting = async () => {
    isChantingRef.current = false;
    setIsRecording(false);

    // Stop recording to get the blob
    if (mediaRecorderRef.current) {
        mediaRecorderRef.current.onstop = async () => {
            setLoading(true);
            const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });

            // Take the last 5 seconds or whole blob for verification
            // Converting blob to base64
            const reader = new FileReader();
            reader.readAsDataURL(audioBlob);
            reader.onloadend = async () => {
                const base64 = reader.result as string;
                // Verify with Gemini
                const result = await verifyChanting(base64);

                setLoading(false);
                if (result.passed) {
                    handleNext();
                } else {
                    setError("System did not detect 'Radha' in your chant. Try again clearly.");
                    setChantCount(0); // Cruel reset
                }
            };
        };
        mediaRecorderRef.current.stop();
    }
  };

  // --- Camera & Reading Handlers ---

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setCameraActive(true);
      }
    } catch (err) {
      setError("Camera access denied.");
    }
  };

  const captureAndVerify = async (mode: 'FACE' | 'QR') => {
    if (!videoRef.current) return;

    // Capture
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const imageBase64 = canvas.toDataURL('image/jpeg');
    setCapturedImage(imageBase64);

    // Stop stream
    const stream = videoRef.current.srcObject as MediaStream;
    stream?.getTracks().forEach(t => t.stop());
    setCameraActive(false);

    setLoading(true);
    let result;
    if (mode === 'FACE') {
      result = await verifyAwakeFace(imageBase64);
    } else {
      result = await verifyQRCodeOrObject(imageBase64);
    }
    setLoading(false);

    if (result.passed) {
      handleNext();
    } else {
      setError(result.message);
      setCapturedImage(null);
    }
  };

  const startReading = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        setLoading(true);
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = reader.result as string;
          const result = await verifySpeech(base64Audio, sentence);
          setLoading(false);
          if (result.passed) {
            handleNext();
          } else {
            setError(result.message);
          }
        };
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      setError("Microphone access denied.");
    }
  };

  const stopReading = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  // Steps Simulation
  const incrementSteps = () => {
      setSteps(prev => {
          const next = prev + 1;
          if (next >= targetSteps) {
              setTimeout(handleNext, 500);
          }
          return next;
      });
  };

  // --- Renderers ---

  if (loading && !isRecording && currentTask !== TaskType.PHOTO_FACE && currentTask !== TaskType.SCAN_QR) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 animate-pulse">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
        <p className="text-zinc-400 font-mono">Verifying Consciousness...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-md mx-auto p-6 space-y-6">
      <div className="w-full flex justify-between items-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
        <span>Task {currentTaskIndex + 1} / {tasks.length}</span>
        <span>{persona} Mode</span>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-zinc-800 rounded-full overflow-hidden">
        <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out" 
            style={{ width: `${((currentTaskIndex) / tasks.length) * 100}%` }}
        />
      </div>

      <div className="w-full bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-xl">
        {error && (
          <div className="mb-4 p-3 bg-red-500/10 border border-red-500/20 text-red-200 text-sm rounded-lg flex items-center gap-2">
            <XCircle className="w-4 h-4" />
            {error}
          </div>
        )}

        {currentTask === TaskType.CHANTING && (
          <div className="space-y-8 text-center">
             <div className="relative">
                <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative overflow-hidden">
                    <div 
                        className="absolute bottom-0 w-full bg-amber-500/20 transition-all duration-300 ease-linear"
                        style={{ height: `${(chantCount / TARGET_CHANTS) * 100}%` }}
                    />
                    <div className="relative z-10 flex flex-col items-center">
                        <span className="text-5xl font-black text-white">{chantCount}</span>
                        <span className="text-xs text-zinc-500 uppercase mt-1">/ {TARGET_CHANTS}</span>
                    </div>
                </div>
                {isRecording && (
                    <div className="absolute inset-0 rounded-full border-4 border-amber-500 animate-ping opacity-20" />
                )}
             </div>

             <div className="space-y-2">
                 <h2 className="text-2xl font-bold text-white">Chant "Radha"</h2>
                 <p className="text-zinc-400 text-sm max-w-[200px] mx-auto">
                    Chant loudly. We are counting your energy.
                 </p>
             </div>

             <button 
                onClick={isRecording ? finishChanting : startChantingSession}
                className={`w-full py-4 font-bold rounded-xl flex items-center justify-center gap-2 transition-all ${
                    isRecording 
                    ? 'bg-amber-600 text-white animate-pulse' 
                    : 'bg-zinc-800 hover:bg-zinc-700 text-zinc-300'
                }`}
             >
                {isRecording ? <Mic className="w-5 h-5" /> : <Zap className="w-5 h-5" />}
                {isRecording ? "Listening..." : "Start Chanting"}
             </button>
          </div>
        )}

        {(currentTask === TaskType.PHOTO_FACE || currentTask === TaskType.SCAN_QR) && (
          <div className="space-y-4 flex flex-col items-center">
            <div className="relative w-full aspect-[4/3] bg-black rounded-xl overflow-hidden border border-zinc-700">
               {!cameraActive && !capturedImage && (
                 <div className="absolute inset-0 flex items-center justify-center text-zinc-600">
                    <Camera className="w-12 h-12 mb-2 opacity-50" />
                 </div>
               )}
               <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : ''}`}
               />
               {capturedImage && (
                 <img src={capturedImage} alt="Captured" className="w-full h-full object-cover" />
               )}
            </div>

            <p className="text-zinc-400 text-center text-sm">
                {currentTask === TaskType.PHOTO_FACE 
                    ? "Take a selfie with your eyes wide open." 
                    : "Scan a QR code or a bathroom object (like a toothbrush)."
                }
            </p>

            {!cameraActive ? (
                <button 
                    onClick={startCamera}
                    className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all"
                >
                    Open Camera
                </button>
            ) : (
                <button 
                    onClick={() => captureAndVerify(currentTask === TaskType.PHOTO_FACE ? 'FACE' : 'QR')}
                    disabled={loading}
                    className="w-full py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all disabled:opacity-50 flex justify-center items-center gap-2"
                >
                    {loading && <Loader2 className="animate-spin w-4 h-4"/>}
                    {loading ? "Analyzing..." : "Capture & Verify"}
                </button>
            )}
          </div>
        )}

        {currentTask === TaskType.READ_SENTENCE && (
          <div className="space-y-6 text-center">
             <div className="p-6 bg-zinc-950 rounded-xl border border-zinc-800">
                <p className="text-lg font-serif italic text-indigo-300">"{sentence}"</p>
             </div>
             <p className="text-zinc-500 text-xs uppercase tracking-widest">Read this loudly</p>

             <button 
                onMouseDown={startReading}
                onMouseUp={stopReading}
                onTouchStart={startReading}
                onTouchEnd={stopReading}
                disabled={loading}
                className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto transition-all ${
                    isRecording 
                    ? 'bg-red-500 scale-110 shadow-lg shadow-red-500/40' 
                    : 'bg-zinc-800 hover:bg-zinc-700'
                }`}
             >
                {loading ? <Loader2 className="animate-spin w-8 h-8 text-zinc-400" /> : <Mic className={`w-8 h-8 ${isRecording ? 'text-white' : 'text-zinc-400'}`} />}
             </button>
             <p className="text-xs text-zinc-600">Hold to record</p>
          </div>
        )}

        {currentTask === TaskType.WALK_STEPS && (
            <div className="space-y-6 text-center">
                <div className="w-32 h-32 mx-auto rounded-full border-4 border-zinc-800 flex items-center justify-center relative">
                    <span className="text-4xl font-black text-white">{steps}</span>
                    <span className="text-xs text-zinc-500 absolute bottom-6">/ {targetSteps}</span>
                </div>
                <div className="space-y-2">
                    <h3 className="text-xl font-bold text-white">Get Moving!</h3>
                    <p className="text-zinc-400 text-sm">Walk around with your device. <br/><span className="text-xs text-zinc-600">(Simulate by tapping the button if no sensor)</span></p>
                </div>
                <button 
                    onClick={incrementSteps}
                    className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2"
                >
                    <Activity className="w-5 h-5" />
                    Simulate Step
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Persona, AlarmConfig, TaskType } from '../types';
import { Bell, Play, Square, Moon, Briefcase, Dumbbell, GraduationCap, User, BookOpen } from 'lucide-react';

interface AlarmClockProps {
  config: AlarmConfig;
  persona: Persona;
  onUpdateConfig: (config: AlarmConfig) => void;
  onUpdatePersona: (persona: Persona) => void;
  onTriggerAlarm: () => void;
}

export const AlarmClock: React.FC<AlarmClockProps> = ({ config, persona, onUpdateConfig, onUpdatePersona, onTriggerAlarm }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      if (config.enabled) {
        const [alarmHour, alarmMinute] = config.time.split(':').map(Number);
        if (now.getHours() === alarmHour && now.getMinutes() === alarmMinute && now.getSeconds() === 0) {
          onTriggerAlarm();
        }
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [config, onTriggerAlarm]);

  const toggleTask = (task: TaskType) => {
    const newTasks = config.tasks.includes(task)
      ? config.tasks.filter(t => t !== task)
      : [...config.tasks, task];
    onUpdateConfig({ ...config, tasks: newTasks });
  };

  const getPersonaIcon = (p: Persona) => {
    switch(p) {
        case Persona.STUDENT: return <BookOpen className="w-5 h-5" />;
        case Persona.CEO: return <Briefcase className="w-5 h-5" />;
        case Persona.GYM_FREAK: return <Dumbbell className="w-5 h-5" />;
        case Persona.SCHOOL_KID: return <GraduationCap className="w-5 h-5" />;
        case Persona.NIGHT_SHIFT_WORKER: return <Moon className="w-5 h-5" />;
        default: return <User className="w-5 h-5" />;
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 space-y-8 max-w-md mx-auto w-full">
      <div className="text-center space-y-2">
        <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400 drop-shadow-lg">
          {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </h1>
        <p className="text-zinc-500 font-medium">{currentTime.toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric'})}</p>
      </div>

      <div className="w-full bg-zinc-900/50 p-6 rounded-3xl border border-zinc-800 shadow-xl backdrop-blur-sm">
        {/* Persona Selector */}
        <div className="mb-6">
          <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Identity Mode</label>
          <div className="grid grid-cols-2 gap-2">
            {Object.values(Persona).map((p) => (
              <button
                key={p}
                onClick={() => onUpdatePersona(p)}
                className={`flex items-center gap-2 p-3 rounded-xl text-sm transition-all duration-200 ${
                  persona === p 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' 
                  : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'
                }`}
              >
                {getPersonaIcon(p)}
                <span className="truncate">{p}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Alarm Time */}
        <div className="mb-6">
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Wake Up Time</label>
            <div className="flex items-center gap-4 bg-zinc-950 p-4 rounded-2xl border border-zinc-800">
                <input 
                    type="time" 
                    value={config.time}
                    onChange={(e) => onUpdateConfig({...config, time: e.target.value})}
                    className="bg-transparent text-3xl font-bold text-white focus:outline-none w-full"
                />
                <button 
                    onClick={() => onUpdateConfig({...config, enabled: !config.enabled})}
                    className={`p-3 rounded-full transition-all ${config.enabled ? 'bg-green-500 text-black' : 'bg-zinc-800 text-zinc-500'}`}
                >
                    <Bell className="w-6 h-6" fill={config.enabled ? "currentColor" : "none"} />
                </button>
            </div>
        </div>

        {/* Tasks */}
        <div>
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Required Challenges</label>
            <div className="space-y-2">
                {[
                    { type: TaskType.CHANTING, label: '108 Radha Chants' },
                    { type: TaskType.PHOTO_FACE, label: 'Verify Awake Face' },
                    { type: TaskType.READ_SENTENCE, label: 'Loud Reading' },
                    { type: TaskType.WALK_STEPS, label: 'Walk 20 Steps' },
                    { type: TaskType.SCAN_QR, label: 'Bathroom Scan' },
                ].map((task) => (
                    <button
                        key={task.type}
                        onClick={() => toggleTask(task.type)}
                        className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${
                            config.tasks.includes(task.type)
                            ? 'border-indigo-500/50 bg-indigo-500/10 text-indigo-200'
                            : 'border-zinc-800 bg-zinc-900 text-zinc-500 hover:border-zinc-700'
                        }`}
                    >
                        <span className="font-medium">{task.label}</span>
                        <div className={`w-5 h-5 rounded-md border flex items-center justify-center ${config.tasks.includes(task.type) ? 'bg-indigo-500 border-indigo-500' : 'border-zinc-600'}`}>
                            {config.tasks.includes(task.type) && <Play className="w-3 h-3 text-white fill-current" />}
