        </div>
      </div>

      {/* Demo Trigger */}
      <button 
        onClick={onTriggerAlarm}
        className="text-xs text-zinc-600 hover:text-zinc-400 underline decoration-zinc-700 underline-offset-4"
      >
        Test Alarm Now
      </button>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AlarmClock } from './components/AlarmClock';
import { TaskFlow } from './components/TaskFlow';
import { AlarmConfig, Persona, TaskType } from './types';
import { generateMotivationalQuote } from './services/geminiService';
import { Volume2, VolumeX } from 'lucide-react';

export default function App() {
  const [persona, setPersona] = useState<Persona>(Persona.STUDENT);
  const [config, setConfig] = useState<AlarmConfig>({
    time: "07:00",
    enabled: false,
    tasks: [TaskType.CHANTING, TaskType.PHOTO_FACE],
    snoozeAllowed: false
  });

  const [isAlarmRinging, setIsAlarmRinging] = useState(false);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [oscillator, setOscillator] = useState<OscillatorNode | null>(null);
  const [quote, setQuote] = useState<string>("");

  // Sound Logic
  const startAlarmSound = () => {
    try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(440, ctx.currentTime);
        // Annoying pulse
        osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

        gain.gain.value = 0.1;

        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();

        setAudioContext(ctx);
        setOscillator(osc);

        // Pulse interval
        const interval = setInterval(() => {
            if(osc.frequency) {
               osc.frequency.setValueAtTime(440, ctx.currentTime); 
               osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);
            }
        }, 1000);
        (osc as any).interval = interval;

    } catch (e) {
        console.error("Audio error", e);
    }
  };

  const stopAlarmSound = () => {
    if (oscillator) {
        clearInterval((oscillator as any).interval);
        oscillator.stop();
        oscillator.disconnect();
    }
    if (audioContext) {
        audioContext.close();
    }
    setOscillator(null);
    setAudioContext(null);
  };

  const handleTriggerAlarm = async () => {
    setIsAlarmRinging(true);
    startAlarmSound();
    const q = await generateMotivationalQuote(persona);
    setQuote(q);
  };

  const handleTasksComplete = () => {
    setIsAlarmRinging(false);
    stopAlarmSound();
    setConfig(prev => ({ ...prev, enabled: false })); // Disable alarm after success
  };

  // If alarm is ringing but user refreshes or closes, we lose state. 
  // In a real PWA, we'd use local storage and Service Workers.
  // For this demo, simple state is enough.

  return (
    <div className="min-h-screen w-full bg-zinc-950 text-zinc-100 flex flex-col relative overflow-hidden">
        {/* Background Gradients */}
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/20 rounded-full blur-[100px] pointer-events-none" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/20 rounded-full blur-[100px] pointer-events-none" />

        {isAlarmRinging ? (
            <div className="z-10 flex flex-col items-center justify-center min-h-screen">
                <div className="absolute top-6 animate-pulse text-red-500 font-black tracking-widest text-2xl flex items-center gap-2">
                    <Volume2 className="w-8 h-8" />
                    ALARM ACTIVE
                    <Volume2 className="w-8 h-8" />
                </div>

                {/* Intro/Motivational Quote before tasks */}
                <div className="mb-8 px-8 text-center max-w-lg">
                     <p className="text-2xl font-bold text-white mb-2">Rise and Shine, {persona}!</p>
                     <p className="text-zinc-400 italic">"{quote}"</p>
                </div>

                <TaskFlow 
                    persona={persona}
                    tasks={config.tasks}
                    onComplete={handleTasksComplete}
                />
            </div>
        ) : (
            <AlarmClock 
                config={config}
                persona={persona}
                onUpdateConfig={setConfig}
                onUpdatePersona={setPersona}
                onTriggerAlarm={handleTriggerAlarm}
            />
        )}
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Persona, TaskType } from '../types';
import { verifyChanting, verifyAwakeFace, verifySpeech, getTongueTwister, verifyQRCodeOrObject } from '../services/geminiService';
import { Loader2, Camera, Mic, Activity, XCircle, Zap, Volume2 } from 'lucide-react';

interface TaskFlowProps {
  persona: Persona;
  tasks: TaskType[];
  onComplete: () => void;
}

export const TaskFlow: React.FC<TaskFlowProps> = ({ persona, tasks, onComplete }) => {
  const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Photo/QR State
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  // Reading State
  const [sentence, setSentence] = useState<string>("");
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Chanting State
  const [chantCount, setChantCount] = useState(0);
  const TARGET_CHANTS = 108;
  const analyserRef = useRef<AnalyserNode | null>(null);
  const chantAudioContextRef = useRef<AudioContext | null>(null);
  const lastChantTimeRef = useRef<number>(0);
  const isChantingRef = useRef(false);
  const [currentVol, setCurrentVol] = useState(0); // For Visualizer

  // Steps State
  const [steps, setSteps] = useState(0);
  const targetSteps = 20;

  const currentTask = tasks[currentTaskIndex];

  // Initialize Task Logic
  useEffect(() => {
    if (!currentTask) {
        onComplete();
        return;
    }

    const initTask = async () => {
      setLoading(true);
      setError(null);
      setCapturedImage(null);
      setIsRecording(false);
      setChantCount(0);
      setCurrentVol(0);
      cleanupChantAudio();

      if (currentTask === TaskType.READ_SENTENCE) {
        const s = await getTongueTwister();
        setSentence(s);
      } else if (currentTask === TaskType.WALK_STEPS) {
        setSteps(0);
      }
      setLoading(false);
    };

    initTask();

    return () => {
      cleanupChantAudio();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTaskIndex, currentTask]);

  const handleNext = () => {
    cleanupChantAudio();
    if (currentTaskIndex + 1 >= tasks.length) {
      onComplete();
    } else {
      setCurrentTaskIndex(prev => prev + 1);
    }
  };

  // --- Chanting Logic ---

  const cleanupChantAudio = () => {
    if (chantAudioContextRef.current) {
        chantAudioContextRef.current.close();
        chantAudioContextRef.current = null;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    isChantingRef.current = false;
  };

  const startChantingSession = async () => {
    setError(null);

    // Check browser support
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Your browser does not support microphone access. Please try a different browser.");
        return;
    }

    try {
        // 1. Create AudioContext immediately on user click (User Gesture)
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioContextClass();
        chantAudioContextRef.current = ctx;

        // 2. Request Mic Permission
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        // 3. Ensure AudioContext is running (sometimes it starts suspended)
        if (ctx.state === 'suspended') {
            await ctx.resume();
        }

        // Setup Media Recorder for Verification
        let mimeType = 'audio/webm';
        if (MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
            mimeType = 'audio/webm;codecs=opus';
        } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
            mimeType = 'audio/mp4'; // Safari
        }

        const mediaRecorder = new MediaRecorder(stream, { mimeType });
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) {
                audioChunksRef.current.push(e.data);
            }
        };

        mediaRecorder.start(1000); // Slice every 1s

        // Setup Audio Analysis for Counting
        const source = ctx.createMediaStreamSource(stream);
        const analyser = ctx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        setIsRecording(true);
        isChantingRef.current = true;

        requestAnimationFrame(detectChantPeak);

    } catch (err: any) {
        console.error("Chanting Setup Error:", err);
        if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
            setError("Microphone permission denied. Please allow access in your browser settings.");
        } else if (err.name === 'NotFoundError') {
            setError("No microphone found on this device.");
        } else {
            setError(`Microphone error: ${err.message || 'Unknown error'}`);
        }
    }
  };

  const detectChantPeak = () => {
    if (!isChantingRef.current || !analyserRef.current) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(dataArray);

    // Calculate Average Volume
    let sum = 0;
    for (let i = 0; i < bufferLength; i++) {
        sum += dataArray[i];
    }
    const average = sum / bufferLength;
    setCurrentVol(average); // Update UI

    // Threshold logic (Dynamic)
    const now = Date.now();
    // Threshold set to 15 (fairly sensitive)
    if (average > 15 && (now - lastChantTimeRef.current > 600)) {
        lastChantTimeRef.current = now;
        setChantCount(prev => {
            const newCount = prev + 1;
            if (newCount >= TARGET_CHANTS) {
                // We don't auto-stop immediately to let them finish the word, 
                // but we could trigger finishChanting logic soon
                return TARGET_CHANTS;
            }
            return newCount;
        });
    }

    if (isChantingRef.current) {
        requestAnimationFrame(detectChantPeak);
    }
  };

  const finishChanting = async () => {
    if (!mediaRecorderRef.current) return;

    isChantingRef.current = false;
    setIsRecording(false);
    setCurrentVol(0);

    // Stop recording to get the blob
    mediaRecorderRef.current.onstop = async () => {
        setLoading(true);
        try {
            // Combine chunks
            const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });

            // Safety check: if audio is empty
            if (audioBlob.size < 100) {
                setLoading(false);
                setError("No audio recorded. Please try again.");
                return;
            }

            const reader = new FileReader();
            reader.readAsDataURL(audioBlob);
            reader.onloadend = async () => {
                const base64 = reader.result as string;
                // Verify with Gemini
                const result = await verifyChanting(base64);

                setLoading(false);
                if (result.passed) {
                    handleNext();
                } else {
                    // Feedback loop: Don't fully reset count if it was close, but strictness varies.
                    // For now, simple error.
                    setError("Could not clearly hear 'Radha'. Please chant clearly.");
                }
            };
        } catch (e) {
            setLoading(false);
            setError("Error processing audio. Please try again.");
        }
    };
    mediaRecorderRef.current.stop();
  };

  // --- Camera & Reading Handlers ---

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setCameraActive(true);
      }
    } catch (err: any) {
      if (err.name === 'NotAllowedError') {
          setError("Camera permission denied.");
      } else {
          setError("Could not access camera.");
      }
    }
  };

  const captureAndVerify = async (mode: 'FACE' | 'QR') => {
    if (!videoRef.current) return;

    // Capture
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const imageBase64 = canvas.toDataURL('image/jpeg');
    setCapturedImage(imageBase64);

    // Stop stream
    const stream = videoRef.current.srcObject as MediaStream;
    stream?.getTracks().forEach(t => t.stop());
    setCameraActive(false);

    setLoading(true);
    let result;
    if (mode === 'FACE') {
      result = await verifyAwakeFace(imageBase64);
    } else {
      result = await verifyQRCodeOrObject(imageBase64);
    }
    setLoading(false);

    if (result.passed) {
      handleNext();
    } else {
      setError(result.message);
      setCapturedImage(null);
    }
  };

  const startReading = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        setLoading(true);
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = reader.result as string;
          const result = await verifySpeech(base64Audio, sentence);
          setLoading(false);
          if (result.passed) {
            handleNext();
          } else {
            setError(result.message);
          }
        };
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      setError("Microphone access denied for reading.");
    }
  };

  const stopReading = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  // Steps Simulation
  const incrementSteps = () => {
      setSteps(prev => {
          const next = prev + 1;
          if (next >= targetSteps) {
              setTimeout(handleNext, 500);
          }
          return next;
      });
  };

  // --- Renderers ---

  if (loading && !isRecording && currentTask !== TaskType.PHOTO_FACE && currentTask !== TaskType.SCAN_QR) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 animate-pulse">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
        <p className="text-zinc-400 font-mono">Verifying Consciousness...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-md mx-auto p-6 space-y-6">
      <div className="w-full flex justify-between items-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
        <span>Task {currentTaskIndex + 1} / {tasks.length}</span>
        <span>{persona} Mode</span>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-zinc-800 rounded-full overflow-hidden">
        <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out" 
            style={{ width: `${((currentTaskIndex) / tasks.length) * 100}%` }}
        />
      </div>

      <div className="w-full bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-xl">
        {error && (
          <div className="mb-4 p-3 bg-red-500/10 border border-red-500/20 text-red-200 text-sm rounded-lg flex items-center gap-2">
            <XCircle className="w-4 h-4" />
            {error}
          </div>
        )}

        {currentTask === TaskType.CHANTING && (
          <div className="space-y-8 text-center">
             <div className="relative">
                {/* Visualizer Ring */}
                <div 
                    className="absolute inset-0 rounded-full border border-amber-500/30 transition-all duration-100 ease-out"
                    style={{ 
                        transform: `scale(${1 + (currentVol / 100)})`,
                        opacity: isRecording ? 0.5 : 0 
                    }}
                />

                <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative overflow-hidden bg-zinc-950 z-10">
                    <div 
                        className="absolute bottom-0 w-full bg-amber-500/20 transition-all duration-300 ease-linear"
                        style={{ height: `${(chantCount / TARGET_CHANTS) * 100}%` }}
                    />
                    <div className="relative z-10 flex flex-col items-center">
                        <span className="text-5xl font-black text-white">{chantCount}</span>
                        <span className="text-xs text-zinc-500 uppercase mt-1">/ {TARGET_CHANTS}</span>
                    </div>
                </div>
             </div>

             <div className="space-y-2">
                 <h2 className="text-2xl font-bold text-white">Chant "Radha"</h2>
                 <p className="text-zinc-400 text-sm max-w-[200px] mx-auto">
                    {isRecording ? "Listening... Speak loudly!" : "Press start and chant loudly to increase energy."}
                 </p>
             </div>

             <div className="flex flex-col gap-3">
                 {!isRecording ? (
                     <button 
                        onClick={startChantingSession}
                        className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all"
                     >
                        <Mic className="w-5 h-5" />
                        Start Microphone
                     </button>
                 ) : (
                    <button 
                        onClick={finishChanting}
                        className={`w-full py-4 font-bold rounded-xl flex items-center justify-center gap-2 transition-all ${
                            chantCount >= TARGET_CHANTS 
                            ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-500/20' 
                            : 'bg-amber-600 text-white animate-pulse'
                        }`}
                    >
                        {chantCount >= TARGET_CHANTS ? (
                            <>
                                <Zap className="w-5 h-5" /> Verify Chants
                            </>
                        ) : (
                            <>
                                <Volume2 className="w-5 h-5" /> Listening...
                            </>
                        )}
                    </button>
                 )}
                 {isRecording && (
                     <p className="text-[10px] text-zinc-600 uppercase tracking-widest">
                         Volume Level: {Math.round(currentVol)}
                     </p>
                 )}
             </div>
          </div>
        )}

        {(currentTask === TaskType.PHOTO_FACE || currentTask === TaskType.SCAN_QR) && (
          <div className="space-y-4 flex flex-col items-center">
            <div className="relative w-full aspect-[4/3] bg-black rounded-xl overflow-hidden border border-zinc-700">
               {!cameraActive && !capturedImage && (
                 <div className="absolute inset-0 flex items-center justify-center text-zinc-600">
                    <Camera className="w-12 h-12 mb-2 opacity-50" />
                 </div>
               )}
               <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : ''}`}
               />
               {capturedImage && (
                 <img src={capturedImage} alt="Captured" className="w-full h-full object-cover" />
               )}
            </div>

            <p className="text-zinc-400 text-center text-sm">
                {currentTask === TaskType.PHOTO_FACE 
                    ? "Take a selfie with your eyes wide open." 
                    : "Scan a QR code or a bathroom object (like a toothbrush)."
                }
            </p>

            {!cameraActive ? (
                <button 
                    onClick={startCamera}
                    className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all"
                >
                    Open Camera
                </button>
            ) : (
                <button 
                    onClick={() => captureAndVerify(currentTask === TaskType.PHOTO_FACE ? 'FACE' : 'QR')}
                    disabled={loading}
                    className="w-full py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all disabled:opacity-50 flex justify-center items-center gap-2"
                >
                    {loading && <Loader2 className="animate-spin w-4 h-4"/>}
                    {loading ? "Analyzing..." : "Capture & Verify"}
                </button>
            )}
          </div>
        )}

        {currentTask === TaskType.READ_SENTENCE && (
          <div className="space-y-6 text-center">
             <div className="p-6 bg-zinc-950 rounded-xl border border-zinc-800">
                <p className="text-lg font-serif italic text-indigo-300">"{sentence}"</p>
             </div>
             <p className="text-zinc-500 text-xs uppercase tracking-widest">Read this loudly</p>

             <button 
                onMouseDown={startReading}
                onMouseUp={stopReading}
                onTouchStart={startReading}
                onTouchEnd={stopReading}
                disabled={loading}
                className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto transition-all ${
                    isRecording 
                    ? 'bg-red-500 scale-110 shadow-lg shadow-red-500/40' 
                    : 'bg-zinc-800 hover:bg-zinc-700'
                }`}
             >
                {loading ? <Loader2 className="animate-spin w-8 h-8 text-zinc-400" /> : <Mic className={`w-8 h-8 ${isRecording ? 'text-white' : 'text-zinc-400'}`} />}
             </button>
             <p className="text-xs text-zinc-600">Hold to record</p>
          </div>
        )}

        {currentTask === TaskType.WALK_STEPS && (
            <div className="space-y-6 text-center">
                <div className="w-32 h-32 mx-auto rounded-full border-4 border-zinc-800 flex items-center justify-center relative">
                    <span className="text-4xl font-black text-white">{steps}</span>
                    <span className="text-xs text-zinc-500 absolute bottom-6">/ {targetSteps}</span>
                </div>
                <div className="space-y-2">
                    <h3 className="text-xl font-bold text-white">Get Moving!</h3>
                    <p className="text-zinc-400 text-sm">Walk around with your device. <br/><span className="text-xs text-zinc-600">(Simulate by tapping the button if no sensor)</span></p>
                </div>
                <button 
                    onClick={incrementSteps}
                    className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2"
                >
                    <Activity className="w-5 h-5" />
                    Simulate Step
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Persona, TaskType } from '../types';
import { verifyChanting, verifyAwakeFace, verifySpeech, getTongueTwister, verifyQRCodeOrObject } from '../services/geminiService';
import { Loader2, Camera, Mic, Activity, XCircle, Zap, Volume2, Hand } from 'lucide-react';

interface TaskFlowProps {
  persona: Persona;
  tasks: TaskType[];
  onComplete: () => void;
}

export const TaskFlow: React.FC<TaskFlowProps> = ({ persona, tasks, onComplete }) => {
  const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Photo/QR State
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  // Reading State
  const [sentence, setSentence] = useState<string>("");
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Chanting State
  const [chantCount, setChantCount] = useState(0);
  const TARGET_CHANTS = 108;
  const analyserRef = useRef<AnalyserNode | null>(null);
  const chantAudioContextRef = useRef<AudioContext | null>(null);
  const lastChantTimeRef = useRef<number>(0);
  const isChantingRef = useRef(false);
  const [currentVol, setCurrentVol] = useState(0); // For Visualizer
  const [manualMode, setManualMode] = useState(false);

  // Steps State
  const [steps, setSteps] = useState(0);
  const targetSteps = 20;

  const currentTask = tasks[currentTaskIndex];

  // Initialize Task Logic
  useEffect(() => {
    if (!currentTask) {
        onComplete();
        return;
    }

    const initTask = async () => {
      setLoading(true);
      setError(null);
      setCapturedImage(null);
      setIsRecording(false);
      setChantCount(0);
      setCurrentVol(0);
      setManualMode(false);
      cleanupChantAudio();

      if (currentTask === TaskType.READ_SENTENCE) {
        const s = await getTongueTwister();
        setSentence(s);
      } else if (currentTask === TaskType.WALK_STEPS) {
        setSteps(0);
      }
      setLoading(false);
    };

    initTask();

    return () => {
      cleanupChantAudio();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTaskIndex, currentTask]);

  const handleNext = () => {
    cleanupChantAudio();
    if (currentTaskIndex + 1 >= tasks.length) {
      onComplete();
    } else {
      setCurrentTaskIndex(prev => prev + 1);
    }
  };

  // --- Chanting Logic ---

  const cleanupChantAudio = () => {
    if (chantAudioContextRef.current) {
        chantAudioContextRef.current.close();
        chantAudioContextRef.current = null;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    isChantingRef.current = false;
  };

  const startChantingSession = async () => {
    setError(null);
    setManualMode(false);

    // Check browser support
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Microphone not supported. Switching to Manual Mode.");
        setManualMode(true);
        return;
    }

    try {
        // 1. Create AudioContext immediately on user click (User Gesture)
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioContextClass();
        chantAudioContextRef.current = ctx;

        // 2. Request Mic Permission
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        // 3. Ensure AudioContext is running (sometimes it starts suspended)
        if (ctx.state === 'suspended') {
            await ctx.resume();
        }

        // Setup Media Recorder for Verification
        let mimeType = 'audio/webm';
        if (MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
            mimeType = 'audio/webm;codecs=opus';
        } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
            mimeType = 'audio/mp4'; // Safari
        }

        const mediaRecorder = new MediaRecorder(stream, { mimeType });
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) {
                audioChunksRef.current.push(e.data);
            }
        };

        mediaRecorder.start(1000); // Slice every 1s

        // Setup Audio Analysis for Counting
        const source = ctx.createMediaStreamSource(stream);
        const analyser = ctx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        setIsRecording(true);
        isChantingRef.current = true;

        requestAnimationFrame(detectChantPeak);

    } catch (err: any) {
        console.error("Chanting Setup Error:", err);
        setManualMode(true);
        if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
            setError("Microphone permission denied. Switched to Manual Mode.");
        } else if (err.name === 'NotFoundError') {
            setError("No microphone found. Switched to Manual Mode.");
        } else {
            setError(`Microphone error: ${err.message || 'Unknown error'}. Switched to Manual Mode.`);
        }
    }
  };

  const detectChantPeak = () => {
    if (!isChantingRef.current || !analyserRef.current) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(dataArray);

    // Calculate Average Volume
    let sum = 0;
    for (let i = 0; i < bufferLength; i++) {
        sum += dataArray[i];
    }
    const average = sum / bufferLength;
    setCurrentVol(average); // Update UI

    // Threshold logic (Dynamic)
    const now = Date.now();
    // Threshold set to 15 (fairly sensitive)
    if (average > 15 && (now - lastChantTimeRef.current > 600)) {
        lastChantTimeRef.current = now;
        setChantCount(prev => {
            const newCount = prev + 1;
            if (newCount >= TARGET_CHANTS) {
                return TARGET_CHANTS;
            }
            return newCount;
        });
    }

    if (isChantingRef.current) {
        requestAnimationFrame(detectChantPeak);
    }
  };

  const finishChanting = async () => {
    if (!mediaRecorderRef.current) return;

    isChantingRef.current = false;
    setIsRecording(false);
    setCurrentVol(0);

    // Stop recording to get the blob
    mediaRecorderRef.current.onstop = async () => {
        setLoading(true);
        try {
            // Combine chunks
            const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });

            // Safety check: if audio is empty
            if (audioBlob.size < 100) {
                setLoading(false);
                setError("No audio recorded. Please try again.");
                return;
            }

            const reader = new FileReader();
            reader.readAsDataURL(audioBlob);
            reader.onloadend = async () => {
                const base64 = reader.result as string;
                // Verify with Gemini
                const result = await verifyChanting(base64);

                setLoading(false);
                if (result.passed) {
                    handleNext();
                } else {
                    setError("Could not clearly hear 'Radha'. Please chant clearly.");
                }
            };
        } catch (e) {
            setLoading(false);
            setError("Error processing audio. Please try again.");
        }
    };
    mediaRecorderRef.current.stop();
  };

  const handleManualTap = () => {
      setChantCount(prev => {
          const newCount = prev + 1;
          if (newCount >= TARGET_CHANTS) {
              setTimeout(handleNext, 300);
              return TARGET_CHANTS;
          }
          return newCount;
      });
      // Visual feedback
      setCurrentVol(50);
      setTimeout(() => setCurrentVol(0), 100);
  };

  // --- Camera & Reading Handlers ---

  const startCamera = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setCameraActive(true);
      }
    } catch (err: any) {
      if (err.name === 'NotAllowedError') {
          setError("Camera permission denied.");
      } else {
          setError("Could not access camera.");
      }
    }
  };

  const captureAndVerify = async (mode: 'FACE' | 'QR') => {
    if (!videoRef.current) return;

    // Capture
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const imageBase64 = canvas.toDataURL('image/jpeg');
    setCapturedImage(imageBase64);

    // Stop stream
    const stream = videoRef.current.srcObject as MediaStream;
    stream?.getTracks().forEach(t => t.stop());
    setCameraActive(false);

    setLoading(true);
    let result;
    if (mode === 'FACE') {
      result = await verifyAwakeFace(imageBase64);
    } else {
      result = await verifyQRCodeOrObject(imageBase64);
    }
    setLoading(false);

    if (result.passed) {
      handleNext();
    } else {
      setError(result.message);
      setCapturedImage(null);
    }
  };

  const startReading = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        setLoading(true);
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = reader.result as string;
          const result = await verifySpeech(base64Audio, sentence);
          setLoading(false);
          if (result.passed) {
            handleNext();
          } else {
            setError(result.message);
          }
        };
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      setError("Microphone access denied for reading.");
    }
  };

  const stopReading = () => {
    mediaRecorderRef.current?.stop();
    setIsRecording(false);
  };

  // Steps Simulation
  const incrementSteps = () => {
      setSteps(prev => {
          const next = prev + 1;
          if (next >= targetSteps) {
              setTimeout(handleNext, 500);
          }
          return next;
      });
  };

  // --- Renderers ---

  if (loading && !isRecording && currentTask !== TaskType.PHOTO_FACE && currentTask !== TaskType.SCAN_QR) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 animate-pulse">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
        <p className="text-zinc-400 font-mono">Verifying Consciousness...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-md mx-auto p-6 space-y-6">
      <div className="w-full flex justify-between items-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
        <span>Task {currentTaskIndex + 1} / {tasks.length}</span>
        <span>{persona} Mode</span>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-zinc-800 rounded-full overflow-hidden">
        <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out" 
            style={{ width: `${((currentTaskIndex) / tasks.length) * 100}%` }}
        />
      </div>

      <div className="w-full bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-xl">
        {error && (
          <div className="mb-4 p-3 bg-red-500/10 border border-red-500/20 text-red-200 text-sm rounded-lg flex items-center gap-2">
            <XCircle className="w-4 h-4" />
            {error}
          </div>
        )}

        {currentTask === TaskType.CHANTING && (
          <div className="space-y-8 text-center">
             <div className="relative">
                {/* Visualizer Ring */}
                <div 
                    className="absolute inset-0 rounded-full border border-amber-500/30 transition-all duration-100 ease-out"
                    style={{ 
                        transform: `scale(${1 + (currentVol / 100)})`,
                        opacity: (isRecording || manualMode) ? 0.5 : 0 
                    }}
                />

                <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative overflow-hidden bg-zinc-950 z-10">
                    <div 
                        className="absolute bottom-0 w-full bg-amber-500/20 transition-all duration-300 ease-linear"
                        style={{ height: `${(chantCount / TARGET_CHANTS) * 100}%` }}
                    />
                    <div className="relative z-10 flex flex-col items-center">
                        <span className="text-5xl font-black text-white">{chantCount}</span>
                        <span className="text-xs text-zinc-500 uppercase mt-1">/ {TARGET_CHANTS}</span>
                    </div>
                </div>
             </div>

             <div className="space-y-2">
                 <h2 className="text-2xl font-bold text-white">Chant "Radha"</h2>
                 <p className="text-zinc-400 text-sm max-w-[200px] mx-auto">
                    {manualMode 
                        ? "Tap the button with every chant."
                        : (isRecording ? "Listening... Speak loudly!" : "Press start and chant loudly to increase energy.")
                    }
                 </p>
             </div>

             <div className="flex flex-col gap-3">
                 {manualMode ? (
                     <button
                        onClick={handleManualTap}
                        className="w-full py-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all active:scale-95"
                     >
                        <Hand className="w-5 h-5" />
                        Tap to Chant ({chantCount})
                     </button>
                 ) : (
                     !isRecording ? (
                         <button 
                            onClick={startChantingSession}
                            className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all"
                         >
                            <Mic className="w-5 h-5" />
                            Start Microphone
                         </button>
                     ) : (
                        <button 
                            onClick={finishChanting}
                            className={`w-full py-4 font-bold rounded-xl flex items-center justify-center gap-2 transition-all ${
                                chantCount >= TARGET_CHANTS 
                                ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-500/20' 
                                : 'bg-amber-600 text-white animate-pulse'
                            }`}
                        >
                            {chantCount >= TARGET_CHANTS ? (
                                <>
                                    <Zap className="w-5 h-5" /> Verify Chants
                                </>
                            ) : (
                                <>
                                    <Volume2 className="w-5 h-5" /> Listening...
                                </>
                            )}
                        </button>
                     )
                 )}

                 {(isRecording && !manualMode) && (
                     <p className="text-[10px] text-zinc-600 uppercase tracking-widest">
                         Volume Level: {Math.round(currentVol)}
                     </p>
                 )}
             </div>
          </div>
        )}

        {(currentTask === TaskType.PHOTO_FACE || currentTask === TaskType.SCAN_QR) && (
          <div className="space-y-4 flex flex-col items-center">
            <div className="relative w-full aspect-[4/3] bg-black rounded-xl overflow-hidden border border-zinc-700">
               {!cameraActive && !capturedImage && (
                 <div className="absolute inset-0 flex items-center justify-center text-zinc-600">
                    <Camera className="w-12 h-12 mb-2 opacity-50" />
                 </div>
               )}
               <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : ''}`}
               />
               {capturedImage && (
                 <img src={capturedImage} alt="Captured" className="w-full h-full object-cover" />
               )}
            </div>

            <p className="text-zinc-400 text-center text-sm">
                {currentTask === TaskType.PHOTO_FACE 
                    ? "Take a selfie with your eyes wide open." 
                    : "Scan a QR code or a bathroom object (like a toothbrush)."
                }
            </p>

            {!cameraActive ? (
                <button 
                    onClick={startCamera}
                    className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all"
                >
                    Open Camera
                </button>
            ) : (
                <button 
                    onClick={() => captureAndVerify(currentTask === TaskType.PHOTO_FACE ? 'FACE' : 'QR')}
                    disabled={loading}
                    className="w-full py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all disabled:opacity-50 flex justify-center items-center gap-2"
                >
                    {loading && <Loader2 className="animate-spin w-4 h-4"/>}
                    {loading ? "Analyzing..." : "Capture & Verify"}
                </button>
            )}
          </div>
        )}

        {currentTask === TaskType.READ_SENTENCE && (
          <div className="space-y-6 text-center">
             <div className="p-6 bg-zinc-950 rounded-xl border border-zinc-800">
                <p className="text-lg font-serif italic text-indigo-300">"{sentence}"</p>
             </div>
             <p className="text-zinc-500 text-xs uppercase tracking-widest">Read this loudly</p>

             <button 
                onMouseDown={startReading}
                onMouseUp={stopReading}
                onTouchStart={startReading}
                onTouchEnd={stopReading}
                disabled={loading}
                className={`w-24 h-24 rounded-full flex items-center justify-center mx-auto transition-all ${
                    isRecording 
                    ? 'bg-red-500 scale-110 shadow-lg shadow-red-500/40' 
                    : 'bg-zinc-800 hover:bg-zinc-700'
                }`}
             >
                {loading ? <Loader2 className="animate-spin w-8 h-8 text-zinc-400" /> : <Mic className={`w-8 h-8 ${isRecording ? 'text-white' : 'text-zinc-400'}`} />}
             </button>
             <p className="text-xs text-zinc-600">Hold to record</p>
          </div>
        )}

        {currentTask === TaskType.WALK_STEPS && (
            <div className="space-y-6 text-center">
                <div className="w-32 h-32 mx-auto rounded-full border-4 border-zinc-800 flex items-center justify-center relative">
                    <span className="text-4xl font-black text-white">{steps}</span>
                    <span className="text-xs text-zinc-500 absolute bottom-6">/ {targetSteps}</span>
                </div>
                <div className="space-y-2">
                    <h3 className="text-xl font-bold text-white">Get Moving!</h3>
                    <p className="text-zinc-400 text-sm">Walk around with your device. <br/><span className="text-xs text-zinc-600">(Simulate by tapping the button if no sensor)</span></p>
                </div>
                <button 
                    onClick={incrementSteps}
                    className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2"
                >
                    <Activity className="w-5 h-5" />
                    Simulate Step
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Persona, TaskType } from '../types';
import { verifyChanting, verifyAwakeFace, verifySpeech, getTongueTwister, verifyQRCodeOrObject } from '../services/geminiService';
import { Loader2, Camera, Mic, Activity, XCircle, Zap, Volume2, Hand } from 'lucide-react';

interface TaskFlowProps {
  persona: Persona;
  tasks: TaskType[];
  onComplete: () => void;
}

export const TaskFlow: React.FC<TaskFlowProps> = ({ persona, tasks, onComplete }) => {
  const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Photo/QR State
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  // Reading State
  const [sentence, setSentence] = useState<string>("");
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Chanting State
  const [chantCount, setChantCount] = useState(0);
  const TARGET_CHANTS = 108;
  const analyserRef = useRef<AnalyserNode | null>(null);
  const chantAudioContextRef = useRef<AudioContext | null>(null);
  const lastChantTimeRef = useRef<number>(0);
  const isChantingRef = useRef(false);
  const [currentVol, setCurrentVol] = useState(0); // For Visualizer
  const [manualMode, setManualMode] = useState(false);

  // Steps State
  const [steps, setSteps] = useState(0);
  const targetSteps = 20;

  const currentTask = tasks[currentTaskIndex];

  // Initialize Task Logic
  useEffect(() => {
    if (!currentTask) {
        onComplete();
        return;
    }

    const initTask = async () => {
      setLoading(true);
      setError(null);
      setCapturedImage(null);
      setIsRecording(false);
      setChantCount(0);
      setCurrentVol(0);
      setManualMode(false);
      cleanupChantAudio();

      if (currentTask === TaskType.READ_SENTENCE) {
        const s = await getTongueTwister();
        setSentence(s);
      } else if (currentTask === TaskType.WALK_STEPS) {
        setSteps(0);
      }
      setLoading(false);
    };

    initTask();

    return () => {
      cleanupChantAudio();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTaskIndex, currentTask]);

  const handleNext = () => {
    cleanupChantAudio();
    if (currentTaskIndex + 1 >= tasks.length) {
      onComplete();
    } else {
      setCurrentTaskIndex(prev => prev + 1);
    }
  };

  // --- Chanting Logic ---

  const cleanupChantAudio = () => {
    if (chantAudioContextRef.current) {
        chantAudioContextRef.current.close();
        chantAudioContextRef.current = null;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    isChantingRef.current = false;
  };

  const startChantingSession = async () => {
    setError(null);
    setManualMode(false);

    // Check browser support
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Microphone not supported. Switching to Manual Mode.");
        setManualMode(true);
        return;
    }

    try {
        // 1. Create AudioContext immediately on user click (User Gesture)
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioContextClass();
        chantAudioContextRef.current = ctx;

        // 2. Request Mic Permission
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        // 3. Ensure AudioContext is running (sometimes it starts suspended)
        if (ctx.state === 'suspended') {
            await ctx.resume();
        }

        // Setup Media Recorder for Verification
        let mimeType = 'audio/webm';
        if (MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
            mimeType = 'audio/webm;codecs=opus';
        } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
            mimeType = 'audio/mp4'; // Safari
        }

        const mediaRecorder = new MediaRecorder(stream, { mimeType });
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) {
                audioChunksRef.current.push(e.data);
            }
        };

        mediaRecorder.start(1000); // Slice every 1s

        // Setup Audio Analysis for Counting
        const source = ctx.createMediaStreamSource(stream);
        const analyser = ctx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        setIsRecording(true);
        isChantingRef.current = true;

        requestAnimationFrame(detectChantPeak);

    } catch (err: any) {
        console.error("Chanting Setup Error:", err);
        setManualMode(true);
        if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
            setError("Microphone permission denied. Switched to Manual Mode.");
        } else if (err.name === 'NotFoundError') {
            setError("No microphone found. Switched to Manual Mode.");
        } else {
            setError(`Microphone error: ${err.message || 'Unknown error'}. Switched to Manual Mode.`);
        }
    }
  };

  const detectChantPeak = () => {
    if (!isChantingRef.current || !analyserRef.current) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(dataArray);

    // Calculate Average Volume
    let sum = 0;
    for (let i = 0; i < bufferLength; i++) {
        sum += dataArray[i];
    }
    const average = sum / bufferLength;
    setCurrentVol(average); // Update UI

    // Threshold logic (Dynamic)
    const now = Date.now();
    // Threshold set to 15 (fairly sensitive)
    if (average > 15 && (now - lastChantTimeRef.current > 600)) {
        lastChantTimeRef.current = now;
        setChantCount(prev => {
            const newCount = prev + 1;
            if (newCount >= TARGET_CHANTS) {
                return TARGET_CHANTS;
            }
            return newCount;
        });
    }

    if (isChantingRef.current) {
        requestAnimationFrame(detectChantPeak);
    }
  };

  const finishChanting = async () => {
    if (!mediaRecorderRef.current) return;

    isChantingRef.current = false;
    setIsRecording(false);
    setCurrentVol(0);

    // Stop recording to get the blob
    mediaRecorderRef.current.onstop = async () => {
        setLoading(true);
        try {
            // Combine chunks
            const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });

            // Safety check: if audio is empty
            if (audioBlob.size < 100) {
                setLoading(false);
                setError("No audio recorded. Please try again.");
                return;
            }

            const reader = new FileReader();
            reader.readAsDataURL(audioBlob);
            reader.onloadend = async () => {
                const base64 = reader.result as string;
                // Verify with Gemini
                const result = await verifyChanting(base64);

                setLoading(false);
                if (result.passed) {
                    handleNext();
                } else {
                    setError("Could not clearly hear 'Radha'. Please chant clearly.");
                }
            };
        } catch (e) {
            setLoading(false);
            setError("Error processing audio. Please try again.");
        }
    };
    mediaRecorderRef.current.stop();
  };

  const handleManualTap = () => {
      setChantCount(prev => {
          const newCount = prev + 1;
          if (newCount >= TARGET_CHANTS) {
              setTimeout(handleNext, 300);
              return TARGET_CHANTS;
          }
          return newCount;
      });
      // Visual feedback
      setCurrentVol(50);
      setTimeout(() => setCurrentVol(0), 100);
  };

  // --- Camera & Reading Handlers ---

  const startCamera = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
        setCameraActive(true);
      }
    } catch (err: any) {
      console.error("Camera Error:", err);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
          setError("Camera permission denied. Please allow access in your browser settings.");
      } else if (err.name === 'NotFoundError') {
          setError("No camera device found on this system.");
      } else if (err.name === 'NotReadableError') {
          setError("Camera is currently in use by another application.");
      } else {
          setError("Could not access camera: " + (err.message || "Unknown error"));
      }
    }
  };

  const captureAndVerify = async (mode: 'FACE' | 'QR') => {
    if (!videoRef.current) return;

    // Capture
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);
    const imageBase64 = canvas.toDataURL('image/jpeg');
    setCapturedImage(imageBase64);

    // Stop stream
    const stream = videoRef.current.srcObject as MediaStream;
    stream?.getTracks().forEach(t => t.stop());
    setCameraActive(false);

    setLoading(true);
    let result;
    if (mode === 'FACE') {
      result = await verifyAwakeFace(imageBase64);
    } else {
      result = await verifyQRCodeOrObject(imageBase64);
    }
    setLoading(false);

    if (result.passed) {
      handleNext();
    } else {
      setError(result.message);
      setCapturedImage(null);
    }
  };

  const startReading = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        setLoading(true);
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = reader.result as string;
          const result = await verifySpeech(base64Audio, sentence);
          setLoading(false);
          if (result.passed) {
            handleNext();
          } else {
            setError(result.message);
          }
        };
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err: any) {
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
         setError("Microphone permission denied for reading.");
      } else {
         setError("Could not access microphone.");
      }
    }
  };

  const stopReading = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    setIsRecording(false);
  };

  // Steps Simulation
  const incrementSteps = () => {
      setSteps(prev => {
          const next = prev + 1;
          if (next >= targetSteps) {
              setTimeout(handleNext, 500);
          }
          return next;
      });
  };

  // --- Renderers ---

  if (loading && !isRecording && currentTask !== TaskType.PHOTO_FACE && currentTask !== TaskType.SCAN_QR) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 animate-pulse">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
        <p className="text-zinc-400 font-mono">Verifying Consciousness...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-md mx-auto p-6 space-y-6">
      <div className="w-full flex justify-between items-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
        <span>Task {currentTaskIndex + 1} / {tasks.length}</span>
        <span>{persona} Mode</span>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-zinc-800 rounded-full overflow-hidden">
        <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out" 
            style={{ width: `${((currentTaskIndex) / tasks.length) * 100}%` }}
        />
      </div>

      <div className="w-full bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-xl">
        {error && (
          <div className="mb-4 p-3 bg-red-500/10 border border-red-500/20 text-red-200 text-sm rounded-lg flex items-center gap-2">
            <XCircle className="w-4 h-4" />
            {error}
          </div>
        )}

        {currentTask === TaskType.CHANTING && (
          <div className="space-y-8 text-center">
             <div className="relative">
                {/* Visualizer Ring */}
                <div 
                    className="absolute inset-0 rounded-full border border-amber-500/30 transition-all duration-100 ease-out"
                    style={{ 
                        transform: `scale(${1 + (currentVol / 100)})`,
                        opacity: (isRecording || manualMode) ? 0.5 : 0 
                    }}
                />

                <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative overflow-hidden bg-zinc-950 z-10">
                    <div 
                        className="absolute bottom-0 w-full bg-amber-500/20 transition-all duration-300 ease-linear"
                        style={{ height: `${(chantCount / TARGET_CHANTS) * 100}%` }}
                    />
                    <div className="relative z-10 flex flex-col items-center">
                        <span className="text-5xl font-black text-white">{chantCount}</span>
                        <span className="text-xs text-zinc-500 uppercase mt-1">/ {TARGET_CHANTS}</span>
                    </div>
                </div>
             </div>

             <div className="space-y-2">
                 <h2 className="text-2xl font-bold text-white">Chant "Radha"</h2>
                 <p className="text-zinc-400 text-sm max-w-[200px] mx-auto">
                    {manualMode 
                        ? "Tap the button with every chant."
                        : (isRecording ? "Listening... Speak loudly!" : "Press start and chant loudly to increase energy.")
                    }
                 </p>
             </div>

             <div className="flex flex-col gap-3">
                 {manualMode ? (
                     <button
                        onClick={handleManualTap}
                        className="w-full py-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all active:scale-95"
                     >
                        <Hand className="w-5 h-5" />
                        Tap to Chant ({chantCount})
                     </button>
                 ) : (
                     !isRecording ? (
                         <button 
                            onClick={startChantingSession}
                            className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all"
                         >
                            <Mic className="w-5 h-5" />
                            Start Microphone
                         </button>
                     ) : (
                        <button 
                            onClick={finishChanting}
                            className={`w-full py-4 font-bold rounded-xl flex items-center justify-center gap-2 transition-all ${
                                chantCount >= TARGET_CHANTS 
                                ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-500/20' 
                                : 'bg-amber-600 text-white animate-pulse'
                            }`}
                        >
                            {chantCount >= TARGET_CHANTS ? (
                                <>
                                    <Zap className="w-5 h-5" /> Verify Chants
                                </>
                            ) : (
                                <>
                                    <Volume2 className="w-5 h-5" /> Listening...
                                </>
                            )}
                        </button>
                     )
                 )}

                 {(isRecording && !manualMode) && (
                     <p className="text-[10px] text-zinc-600 uppercase tracking-widest">
                         Volume Level: {Math.round(currentVol)}
                     </p>
                 )}
             </div>
          </div>
        )}

        {(currentTask === TaskType.PHOTO_FACE || currentTask === TaskType.SCAN_QR) && (
          <div className="space-y-4 flex flex-col items-center">
            <div className="relative w-full aspect-[4/3] bg-black rounded-xl overflow-hidden border border-zinc-700">
               {!cameraActive && !capturedImage && (
                 <div className="absolute inset-0 flex items-center justify-center text-zinc-600">
                    <Camera className="w-12 h-12 mb-2 opacity-50" />
                 </div>
               )}
               <video 
                ref={videoRef} 
                autoPlay 
                muted 
                playsInline 
                className={`w-full h-full object-cover ${!cameraActive ? 'hidden' : ''}`}
               />
               {capturedImage && (
                 <img src={capturedImage} alt="Captured" className="w-full h-full object-cover" />
               )}
            </div>

            <p className="text-zinc-400 text-center text-sm">
                {currentTask === TaskType.PHOTO_FACE 
                    ? "Take a selfie with your eyes wide open." 
                    : "Scan a QR code or a bathroom object (like a toothbrush)."
                }
            </p>

            {!cameraActive ? (
                <button 
                    onClick={startCamera}
                    className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all"
                >
                    Open Camera
                </button>
            ) : (
                <button 
                    onClick={() => captureAndVerify(currentTask === TaskType.PHOTO_FACE ? 'FACE' : 'QR')}
                    disabled={loading}
                    className="w-full py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all disabled:opacity-50 flex justify-center items-center gap-2"
                >
                    {loading && <Loader2 className="animate-spin w-4 h-4"/>}
                    {loading ? "Analyzing..." : "Capture & Verify"}
                </button>
            )}
          </div>
        )}

        {currentTask === TaskType.READ_SENTENCE && (
          <div className="space-y-8 text-center flex flex-col items-center">
             <div className="w-full p-8 bg-gradient-to-br from-zinc-900 to-zinc-950 rounded-2xl border border-zinc-800 shadow-inner">
                <p className="text-2xl font-serif italic text-indigo-300 leading-relaxed">
                    "{sentence || "Loading sentence..."}"
                </p>
             </div>

             <div className="space-y-4 w-full flex flex-col items-center">
                 <p className="text-zinc-500 text-xs uppercase tracking-widest font-bold">
                    {isRecording ? "Listening..." : "Hold Button & Read Loudly"}
                 </p>

                 <button 
                    onMouseDown={startReading}
                    onMouseUp={stopReading}
                    onTouchStart={startReading}
                    onTouchEnd={stopReading}
                    disabled={loading}
                    className={`
                        relative w-32 h-32 rounded-full flex items-center justify-center transition-all duration-200
                        ${isRecording 
                            ? 'bg-red-500 scale-110 shadow-[0_0_40px_rgba(239,68,68,0.4)]' 
                            : 'bg-zinc-800 hover:bg-zinc-700 hover:scale-105 shadow-xl'
                        }
                        ${loading ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
                    `}
                 >
                    {isRecording && (
                        <div className="absolute inset-0 rounded-full border-4 border-white/30 animate-ping" />
                    )}

                    {loading ? (
                        <Loader2 className="animate-spin w-10 h-10 text-white/50" /> 
                    ) : (
                        <Mic className={`w-10 h-10 ${isRecording ? 'text-white' : 'text-zinc-400'}`} />
                    )}
                 </button>

                 {isRecording && (
                    <p className="text-red-400 text-sm animate-pulse font-medium">
                        Release to Verify
                    </p>
                 )}
             </div>
          </div>
        )}

        {currentTask === TaskType.WALK_STEPS && (
            <div className="space-y-6 text-center">
                <div className="w-32 h-32 mx-auto rounded-full border-4 border-zinc-800 flex items-center justify-center relative">
                    <span className="text-4xl font-black text-white">{steps}</span>
                    <span className="text-xs text-zinc-500 absolute bottom-6">/ {targetSteps}</span>
                </div>
                <div className="space-y-2">
                    <h3 className="text-xl font-bold text-white">Get Moving!</h3>
                    <p className="text-zinc-400 text-sm">Walk around with your device. <br/><span className="text-xs text-zinc-600">(Simulate by tapping the button if no sensor)</span></p>
                </div>
                <button 
                    onClick={incrementSteps}
                    className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2"
                >
                    <Activity className="w-5 h-5" />
                    Simulate Step
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

