};

import React, { useState, useEffect } from 'react';
import { AlarmClock } from './components/AlarmClock';
import { TaskFlow } from './components/TaskFlow';
import { AlarmConfig, Persona, TaskType } from './types';
import { generateMotivationalQuote } from './services/geminiService';
import { Volume2, VolumeX } from 'lucide-react';

export default function App() {
  const [persona, setPersona] = useState<Persona>(Persona.STUDENT);
  const [config, setConfig] = useState<AlarmConfig>({
    time: "07:00",
    enabled: false,
    tasks: [TaskType.CHANTING, TaskType.PHOTO_FACE],
    snoozeAllowed: false
  });

  const [isAlarmRinging, setIsAlarmRinging] = useState(false);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [oscillator, setOscillator] = useState<OscillatorNode | null>(null);
  const [quote, setQuote] = useState<string>("");

  // Wake Lock Logic
  useEffect(() => {
    let wakeLock: any = null;

    const requestWakeLock = async () => {
      if ('wakeLock' in navigator) {
        try {
          wakeLock = await (navigator as any).wakeLock.request('screen');
          console.log('Screen Wake Lock acquired');
        } catch (err: any) {
          console.error(`Wake Lock Error: ${err.name}, ${err.message}`);
        }
      }
    };

    const handleVisibilityChange = async () => {
      if (document.visibilityState === 'visible' && isAlarmRinging) {
        await requestWakeLock();
      }
    };

    if (isAlarmRinging) {
      requestWakeLock();
      document.addEventListener('visibilitychange', handleVisibilityChange);
    }

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      if (wakeLock) {
        wakeLock.release().then(() => {
            console.log('Screen Wake Lock released');
        }).catch((e: any) => console.error(e));
      }
    };
  }, [isAlarmRinging]);

  // Sound Logic
  const startAlarmSound = () => {
    try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(440, ctx.currentTime);
        // Annoying pulse
        osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

        gain.gain.value = 0.1;

        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();

        setAudioContext(ctx);
        setOscillator(osc);

        // Pulse interval
        const interval = setInterval(() => {
            if(osc.frequency) {
               osc.frequency.setValueAtTime(440, ctx.currentTime); 
               osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);
            }
        }, 1000);
        (osc as any).interval = interval;

    } catch (e) {
        console.error("Audio error", e);
    }
  };

  const stopAlarmSound = () => {
    if (oscillator) {
        clearInterval((oscillator as any).interval);
        oscillator.stop();
        oscillator.disconnect();
    }
    if (audioContext) {
        audioContext.close();
    }
    setOscillator(null);
    setAudioContext(null);
  };

  const handleTriggerAlarm = async () => {
    setIsAlarmRinging(true);
    startAlarmSound();
    const q = await generateMotivationalQuote(persona);
    setQuote(q);
  };

  const handleTasksComplete = () => {
    setIsAlarmRinging(false);
    stopAlarmSound();
    setConfig(prev => ({ ...prev, enabled: false })); // Disable alarm after success
  };

  // If alarm is ringing but user refreshes or closes, we lose state. 
  // In a real PWA, we'd use local storage and Service Workers.
  // For this demo, simple state is enough.

  return (
    <div className="min-h-screen w-full bg-zinc-950 text-zinc-100 flex flex-col relative overflow-hidden">
        {/* Background Gradients */}
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-900/20 rounded-full blur-[100px] pointer-events-none" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-900/20 rounded-full blur-[100px] pointer-events-none" />

        {isAlarmRinging ? (
            <div className="z-10 flex flex-col items-center justify-center min-h-screen">
                <div className="absolute top-6 animate-pulse text-red-500 font-black tracking-widest text-2xl flex items-center gap-2">
                    <Volume2 className="w-8 h-8" />
                    ALARM ACTIVE
                    <Volume2 className="w-8 h-8" />
                </div>

                {/* Intro/Motivational Quote before tasks */}
                <div className="mb-8 px-8 text-center max-w-lg">
                     <p className="text-2xl font-bold text-white mb-2">Rise and Shine, {persona}!</p>
                     <p className="text-zinc-400 italic">"{quote}"</p>
                </div>

                <TaskFlow 
                    persona={persona}
                    tasks={config.tasks}
                    onComplete={handleTasksComplete}
                />
            </div>
        ) : (
            <AlarmClock 
                config={config}
                persona={persona}
                onUpdateConfig={setConfig}
                onUpdatePersona={setPersona}
                onTriggerAlarm={handleTriggerAlarm}
            />
        )}
    </div>
  );
}

