import React, { useState, useEffect } from 'react';
import { Persona, AlarmConfig, TaskType } from '../types';
import { Bell, Play, Square, Moon, Briefcase, Dumbbell, GraduationCap, User, BookOpen } from 'lucide-react';

interface AlarmClockProps {
  config: AlarmConfig;
  persona: Persona;
  onUpdateConfig: (config: AlarmConfig) => void;
  onUpdatePersona: (persona: Persona) => void;
  onTriggerAlarm: () => void;
}

export const AlarmClock: React.FC<AlarmClockProps> = ({ config, persona, onUpdateConfig, onUpdatePersona, onTriggerAlarm }) => {
  const [currentTime, setCurrentTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      if (config.enabled) {
        const [alarmHour, alarmMinute] = config.time.split(':').map(Number);
        if (now.getHours() === alarmHour && now.getMinutes() === alarmMinute && now.getSeconds() === 0) {
          onTriggerAlarm();
        }
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [config, onTriggerAlarm]);

  const toggleTask = (task: TaskType) => {
    const newTasks = config.tasks.includes(task)
      ? config.tasks.filter(t => t !== task)
      : [...config.tasks, task];
    onUpdateConfig({ ...config, tasks: newTasks });
  };

  const getPersonaIcon = (p: Persona) => {
    switch(p) {
        case Persona.STUDENT: return <BookOpen className="w-5 h-5" />;
        case Persona.CEO: return <Briefcase className="w-5 h-5" />;
        case Persona.GYM_FREAK: return <Dumbbell className="w-5 h-5" />;
        case Persona.SCHOOL_KID: return <GraduationCap className="w-5 h-5" />;
        case Persona.NIGHT_SHIFT_WORKER: return <Moon className="w-5 h-5" />;
        default: return <User className="w-5 h-5" />;
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 space-y-8 max-w-md mx-auto w-full">
      <div className="text-center space-y-2">
        <h1 className="text-6xl font-black tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-purple-400 drop-shadow-lg">
          {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </h1>
        <p className="text-zinc-500 font-medium">{currentTime.toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric'})}</p>
      </div>

      <div className="w-full bg-zinc-900/50 p-6 rounded-3xl border border-zinc-800 shadow-xl backdrop-blur-sm">
        {/* Persona Selector */}
        <div className="mb-6">
          <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Identity Mode</label>
          <div className="grid grid-cols-2 gap-2">
            {Object.values(Persona).map((p) => (
              <button
                key={p}
                onClick={() => onUpdatePersona(p)}
                className={`flex items-center gap-2 p-3 rounded-xl text-sm transition-all duration-200 ${
                  persona === p 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' 
                  : 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700'
                }`}
              >
                {getPersonaIcon(p)}
                <span className="truncate">{p}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Alarm Time */}
        <div className="mb-6">
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Wake Up Time</label>
            <div className="flex items-center gap-4 bg-zinc-950 p-4 rounded-2xl border border-zinc-800">
                <input 
                    type="time" 
                    value={config.time}
                    onChange={(e) => onUpdateConfig({...config, time: e.target.value})}
                    className="bg-transparent text-3xl font-bold text-white focus:outline-none w-full"
                />
                <button 
                    onClick={() => onUpdateConfig({...config, enabled: !config.enabled})}
                    className={`p-3 rounded-full transition-all ${config.enabled ? 'bg-green-500 text-black' : 'bg-zinc-800 text-zinc-500'}`}
                >
                    <Bell className="w-6 h-6" fill={config.enabled ? "currentColor" : "none"} />
                </button>
            </div>
        </div>

        {/* Tasks */}
        <div>
            <label className="text-xs font-bold text-zinc-500 uppercase tracking-wider mb-3 block">Required Challenges</label>
            <div className="space-y-2">
                {[
                    { type: TaskType.CHANTING, label: '108 Radha Chants' },
                    { type: TaskType.PHOTO_FACE, label: 'Verify Awake Face' },
                    { type: TaskType.READ_SENTENCE, label: 'Loud Reading' },
                    { type: TaskType.WALK_STEPS, label: 'Walk 20 Steps' },
                    { type: TaskType.SCAN_QR, label: 'Bathroom Scan' },
                ].map((task) => (
                    <button
                        key={task.type}
                        onClick={() => toggleTask(task.type)}
                        className={`w-full flex items-center justify-between p-3 rounded-xl border transition-all ${
                            config.tasks.includes(task.type)
                            ? 'border-indigo-500/50 bg-indigo-500/10 text-indigo-200'
                            : 'border-zinc-800 bg-zinc-900 text-zinc-500 hover:border-zinc-700'
                        }`}
                    >
                        <span className="font-medium">{task.label}</span>
                        <div className={`w-5 h-5 rounded-md border flex items-center justify-center ${config.tasks.includes(task.type) ? 'bg-indigo-500 border-indigo-500' : 'border-zinc-600'}`}>
                            {config.tasks.includes(task.type) && <Play className="w-3 h-3 text-white fill-current" />}
                        </div>
                    </button>
                ))}
            </div>
        </div>
      </div>

      {/* Demo Trigger */}
      <button 
        onClick={onTriggerAlarm}
        className="text-xs text-zinc-600 hover:text-zinc-400 underline decoration-zinc-700 underline-offset-4"
      >
        Test Alarm Now
      </button>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Persona, TaskType } from '../types';
import { verifyChanting, verifyAwakeFace, verifySpeech, getTongueTwister, verifyQRCodeOrObject } from '../services/geminiService';
import { Loader2, Camera, Mic, Activity, XCircle, Zap, Volume2, Hand, Settings } from 'lucide-react';

interface TaskFlowProps {
  persona: Persona;
  tasks: TaskType[];
  onComplete: () => void;
}

export const TaskFlow: React.FC<TaskFlowProps> = ({ persona, tasks, onComplete }) => {
  const [currentTaskIndex, setCurrentTaskIndex] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Photo/QR State
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  // Reading State
  const [sentence, setSentence] = useState<string>("");
  const [isRecording, setIsRecording] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Chanting State
  const [chantCount, setChantCount] = useState(0);
  const TARGET_CHANTS = 108;
  const analyserRef = useRef<AnalyserNode | null>(null);
  const chantAudioContextRef = useRef<AudioContext | null>(null);
  const lastChantTimeRef = useRef<number>(0);
  const isChantingRef = useRef(false);
  const [currentVol, setCurrentVol] = useState(0); // For Visualizer
  const [manualMode, setManualMode] = useState(false);

  // Generic Manual Count (reused for Camera fallback)
  const [manualTapCount, setManualTapCount] = useState(0);
  const TARGET_MANUAL_TAPS = 30;

  // Steps State
  const [steps, setSteps] = useState(0);
  const targetSteps = 20;

  const currentTask = tasks[currentTaskIndex];

  // Initialize Task Logic
  useEffect(() => {
    if (!currentTask) {
        onComplete();
        return;
    }

    const initTask = async () => {
      setLoading(true);
      setError(null);
      setCapturedImage(null);
      setIsRecording(false);
      setChantCount(0);
      setCurrentVol(0);
      setManualMode(false);
      setManualTapCount(0);
      setCameraActive(false); // Reset camera UI
      cleanupChantAudio();
      stopCameraStream(); // Ensure previous stream is closed

      if (currentTask === TaskType.READ_SENTENCE) {
        const s = await getTongueTwister();
        setSentence(s);
      } else if (currentTask === TaskType.WALK_STEPS) {
        setSteps(0);
      }
      setLoading(false);
    };

    initTask();

    return () => {
      cleanupChantAudio();
      stopCameraStream();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentTaskIndex, currentTask]);

  const handleNext = () => {
    cleanupChantAudio();
    stopCameraStream();
    if (currentTaskIndex + 1 >= tasks.length) {
      onComplete();
    } else {
      setCurrentTaskIndex(prev => prev + 1);
    }
  };

  // --- Chanting Logic ---

  const cleanupChantAudio = () => {
    if (chantAudioContextRef.current) {
        chantAudioContextRef.current.close();
        chantAudioContextRef.current = null;
    }
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    isChantingRef.current = false;
  };

  const startChantingSession = async () => {
    setError(null);
    setManualMode(false);

    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Microphone not supported. Switching to Manual Mode.");
        setManualMode(true);
        return;
    }

    try {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioContextClass();
        chantAudioContextRef.current = ctx;

        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

        if (ctx.state === 'suspended') {
            await ctx.resume();
        }

        let mimeType = 'audio/webm';
        if (MediaRecorder.isTypeSupported('audio/webm;codecs=opus')) {
            mimeType = 'audio/webm;codecs=opus';
        } else if (MediaRecorder.isTypeSupported('audio/mp4')) {
            mimeType = 'audio/mp4'; 
        }

        const mediaRecorder = new MediaRecorder(stream, { mimeType });
        mediaRecorderRef.current = mediaRecorder;
        audioChunksRef.current = [];

        mediaRecorder.ondataavailable = (e) => {
            if (e.data.size > 0) {
                audioChunksRef.current.push(e.data);
            }
        };

        mediaRecorder.start(1000); 

        const source = ctx.createMediaStreamSource(stream);
        const analyser = ctx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;

        setIsRecording(true);
        isChantingRef.current = true;

        requestAnimationFrame(detectChantPeak);

    } catch (err: any) {
        console.error("Chanting Setup Error:", err);
        setManualMode(true);
        if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError' || err.message?.includes("Permission denied")) {
            setError("Microphone permission denied. Switched to Manual Mode.");
        } else {
            setError(`Microphone error: ${err.message || 'Unknown error'}. Switched to Manual Mode.`);
        }
    }
  };

  const detectChantPeak = () => {
    if (!isChantingRef.current || !analyserRef.current) return;

    const bufferLength = analyserRef.current.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);
    analyserRef.current.getByteFrequencyData(dataArray);

    let sum = 0;
    for (let i = 0; i < bufferLength; i++) {
        sum += dataArray[i];
    }
    const average = sum / bufferLength;
    setCurrentVol(average); 

    const now = Date.now();
    if (average > 15 && (now - lastChantTimeRef.current > 600)) {
        lastChantTimeRef.current = now;
        setChantCount(prev => {
            const newCount = prev + 1;
            if (newCount >= TARGET_CHANTS) {
                return TARGET_CHANTS;
            }
            return newCount;
        });
    }

    if (isChantingRef.current) {
        requestAnimationFrame(detectChantPeak);
    }
  };

  const finishChanting = async () => {
    if (!mediaRecorderRef.current) return;

    isChantingRef.current = false;
    setIsRecording(false);
    setCurrentVol(0);

    mediaRecorderRef.current.onstop = async () => {
        setLoading(true);
        try {
            const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorderRef.current?.mimeType || 'audio/webm' });

            if (audioBlob.size < 100) {
                setLoading(false);
                setError("No audio recorded. Please try again.");
                return;
            }

            const reader = new FileReader();
            reader.readAsDataURL(audioBlob);
            reader.onloadend = async () => {
                const base64 = reader.result as string;
                const result = await verifyChanting(base64);

                setLoading(false);
                if (result.passed) {
                    handleNext();
                } else {
                    setError("Could not clearly hear 'Radha'. Please chant clearly.");
                }
            };
        } catch (e) {
            setLoading(false);
            setError("Error processing audio. Please try again.");
        }
    };
    mediaRecorderRef.current.stop();
  };

  const handleManualChantTap = () => {
      setChantCount(prev => {
          const newCount = prev + 1;
          if (newCount >= TARGET_CHANTS) {
              setTimeout(handleNext, 300);
              return TARGET_CHANTS;
          }
          return newCount;
      });
      setCurrentVol(50);
      setTimeout(() => setCurrentVol(0), 100);
  };

  // --- Camera Logic ---

  const stopCameraStream = () => {
    if (videoRef.current && videoRef.current.srcObject) {
      const stream = videoRef.current.srcObject as MediaStream;
      stream.getTracks().forEach(t => t.stop());
      videoRef.current.srcObject = null;
    }
  };

  const startCamera = async () => {
    setError(null);
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Camera not supported on this device. Manual mode activated.");
        setManualMode(true);
        return;
    }

    try {
      let stream: MediaStream;
      // 1. Try preferred settings (User Facing)
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: "user" } 
        });
      } catch (e) {
        console.warn("Preferred camera failed, trying fallback", e);
        // 2. Fallback to any video source
        stream = await navigator.mediaDevices.getUserMedia({ video: true });
      }

      setCameraActive(true);

      // 3. Assign to video element with slight delay to ensure DOM is ready/visible
      // This helps with some browser painting issues when switching 'hidden' class
      setTimeout(() => {
          if (videoRef.current) {
            videoRef.current.srcObject = stream;
            videoRef.current.onloadedmetadata = () => {
                videoRef.current?.play().catch(e => {
                    console.error("Auto-play failed", e);
                });
            };
          }
      }, 50);

    } catch (err: any) {
      console.error("Camera Error:", err);
      // Auto-switch to manual mode on error
      setManualMode(true);
      stopCameraStream();

      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError' || err.message?.includes("Permission denied")) {
          setError("⚠️ Permission Denied: Camera access blocked. Switched to Manual Mode.");
      } else if (err.name === 'NotFoundError') {
          setError("No camera found. Switched to Manual Mode.");
      } else if (err.name === 'NotReadableError') {
          setError("Camera hardware error. Switched to Manual Mode.");
      } else {
          setError(`Camera Error: ${err.message || "Unknown"}. Switched to Manual Mode.`);
      }
    }
  };

  const handleManualCameraTap = () => {
      setManualTapCount(prev => {
          const next = prev + 1;
          if (next >= TARGET_MANUAL_TAPS) {
              setTimeout(handleNext, 300);
              return TARGET_MANUAL_TAPS;
          }
          return next;
      });
  };

  const captureAndVerify = async (mode: 'FACE' | 'QR') => {
    if (!videoRef.current) return;

    // Capture to canvas
    const canvas = document.createElement('canvas');
    canvas.width = videoRef.current.videoWidth || 640;
    canvas.height = videoRef.current.videoHeight || 480;
    const ctx = canvas.getContext('2d');

    if (ctx) {
        ctx.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const imageBase64 = canvas.toDataURL('image/jpeg', 0.8);
        setCapturedImage(imageBase64);

        // Stop stream immediately after capture
        stopCameraStream();
        setCameraActive(false);

        setLoading(true);
        let result;
        if (mode === 'FACE') {
            result = await verifyAwakeFace(imageBase64);
        } else {
            result = await verifyQRCodeOrObject(imageBase64);
        }
        setLoading(false);

        if (result.passed) {
            handleNext();
        } else {
            setError(result.message);
            setCapturedImage(null); // Allow retry
        }
    } else {
        setError("Could not process image. Please try again.");
    }
  };

  // --- Reading Logic ---

  const startReading = async () => {
    setError(null);
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        audioChunksRef.current.push(event.data);
      };

      mediaRecorder.onstop = async () => {
        setLoading(true);
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = reader.result as string;
          const result = await verifySpeech(base64Audio, sentence);
          setLoading(false);
          if (result.passed) {
            handleNext();
          } else {
            setError(result.message);
          }
        };
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err: any) {
      console.error("Mic Error:", err);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError' || err.message?.includes("Permission denied")) {
         setError("⚠️ Permission Denied: Enable Microphone access.");
      } else {
         setError("Could not access microphone.");
      }
    }
  };

  const stopReading = () => {
    if (mediaRecorderRef.current && mediaRecorderRef.current.state === 'recording') {
        mediaRecorderRef.current.stop();
    }
    setIsRecording(false);
  };

  // --- Steps Logic ---
  const incrementSteps = () => {
      setSteps(prev => {
          const next = prev + 1;
          if (next >= targetSteps) {
              setTimeout(handleNext, 500);
          }
          return next;
      });
  };

  // --- Renderers ---

  if (loading && !isRecording && currentTask !== TaskType.PHOTO_FACE && currentTask !== TaskType.SCAN_QR) {
    return (
      <div className="flex flex-col items-center justify-center h-full space-y-4 animate-pulse">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
        <p className="text-zinc-400 font-mono">Verifying...</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center justify-center w-full max-w-md mx-auto p-6 space-y-6">
      <div className="w-full flex justify-between items-center text-xs font-bold text-zinc-500 uppercase tracking-wider">
        <span>Task {currentTaskIndex + 1} / {tasks.length}</span>
        <span>{persona} Mode</span>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1 bg-zinc-800 rounded-full overflow-hidden">
        <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out" 
            style={{ width: `${((currentTaskIndex) / tasks.length) * 100}%` }}
        />
      </div>

      <div className="w-full bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-xl">
        {error && (
          <div className="mb-4 p-4 bg-amber-900/20 border border-amber-500/50 text-amber-200 text-sm rounded-lg flex flex-col gap-2">
            <div className="flex items-center gap-2 font-bold text-amber-100">
               <XCircle className="w-4 h-4" />
               System Notice
            </div>
            <p>{error}</p>
          </div>
        )}

        {/* CHANTING UI */}
        {currentTask === TaskType.CHANTING && (
          <div className="space-y-8 text-center">
             <div className="relative">
                <div 
                    className="absolute inset-0 rounded-full border border-amber-500/30 transition-all duration-100 ease-out"
                    style={{ 
                        transform: `scale(${1 + (currentVol / 100)})`,
                        opacity: (isRecording || manualMode) ? 0.5 : 0 
                    }}
                />

                <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative overflow-hidden bg-zinc-950 z-10">
                    <div 
                        className="absolute bottom-0 w-full bg-amber-500/20 transition-all duration-300 ease-linear"
                        style={{ height: `${(chantCount / TARGET_CHANTS) * 100}%` }}
                    />
                    <div className="relative z-10 flex flex-col items-center">
                        <span className="text-5xl font-black text-white">{chantCount}</span>
                        <span className="text-xs text-zinc-500 uppercase mt-1">/ {TARGET_CHANTS}</span>
                    </div>
                </div>
             </div>

             <div className="space-y-2">
                 <h2 className="text-2xl font-bold text-white">Chant "Radha"</h2>
                 <p className="text-zinc-400 text-sm max-w-[200px] mx-auto">
                    {manualMode 
                        ? "Microphone unavailable. Tap button repeatedly."
                        : (isRecording ? "Listening... Speak loudly!" : "Press start and chant loudly.")
                    }
                 </p>
             </div>

             <div className="flex flex-col gap-3">
                 {manualMode ? (
                     <button
                        onClick={handleManualChantTap}
                        className="w-full py-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all active:scale-95 shadow-lg shadow-amber-900/20"
                     >
                        <Hand className="w-5 h-5" />
                        Tap to Chant ({chantCount})
                     </button>
                 ) : (
                     !isRecording ? (
                         <button 
                            onClick={startChantingSession}
                            className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 transition-all"
                         >
                            <Mic className="w-5 h-5" />
                            Start Microphone
                         </button>
                     ) : (
                        <button 
                            onClick={finishChanting}
                            className={`w-full py-4 font-bold rounded-xl flex items-center justify-center gap-2 transition-all ${
                                chantCount >= TARGET_CHANTS 
                                ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-500/20' 
                                : 'bg-amber-600 text-white animate-pulse'
                            }`}
                        >
                            {chantCount >= TARGET_CHANTS ? (
                                <>
                                    <Zap className="w-5 h-5" /> Verify Chants
                                </>
                            ) : (
                                <>
                                    <Volume2 className="w-5 h-5" /> Listening...
                                </>
                            )}
                        </button>
                     )
                 )}
             </div>
          </div>
        )}

        {/* CAMERA TASKS UI */}
        {(currentTask === TaskType.PHOTO_FACE || currentTask === TaskType.SCAN_QR) && (
          <div className="space-y-4 flex flex-col items-center w-full">
             {!manualMode ? (
                <>
                    <div className="relative w-full aspect-[4/3] bg-black rounded-xl overflow-hidden border border-zinc-700 shadow-inner">
                        {!cameraActive && !capturedImage && (
                            <div className="absolute inset-0 flex flex-col items-center justify-center text-zinc-600 space-y-2">
                                <Camera className="w-12 h-12 opacity-50" />
                                <p className="text-xs uppercase tracking-widest">Camera Inactive</p>
                            </div>
                        )}
                        <video 
                            ref={videoRef} 
                            autoPlay 
                            muted 
                            playsInline 
                            className={`w-full h-full object-cover transform scale-x-[-1] ${!cameraActive ? 'hidden' : ''}`}
                        />
                        {capturedImage && (
                            <img src={capturedImage} alt="Captured" className="w-full h-full object-cover transform scale-x-[-1]" />
                        )}
                    </div>

                    <p className="text-zinc-400 text-center text-sm px-4">
                        {currentTask === TaskType.PHOTO_FACE 
                            ? "Prove you are awake. Take a selfie with your eyes wide open." 
                            : "Scan a bathroom object (like a toothbrush) or QR code."
                        }
                    </p>

                    {!cameraActive ? (
                        <button 
                            onClick={startCamera}
                            className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl transition-all flex items-center justify-center gap-2 shadow-lg shadow-indigo-900/20"
                        >
                            <Camera className="w-5 h-5" />
                            Open Camera
                        </button>
                    ) : (
                        <button 
                            onClick={() => captureAndVerify(currentTask === TaskType.PHOTO_FACE ? 'FACE' : 'QR')}
                            disabled={loading}
                            className="w-full py-4 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-all disabled:opacity-50 flex justify-center items-center gap-2 shadow-lg"
                        >
                            {loading && <Loader2 className="animate-spin w-4 h-4"/>}
                            {loading ? "Analyzing..." : "Capture & Verify"}
                        </button>
                    )}
                </>
             ) : (
                 /* Manual Fallback Mode for Camera */
                 <div className="w-full py-8 flex flex-col items-center space-y-6">
                     <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative bg-zinc-950">
                        <div 
                            className="absolute bottom-0 w-full bg-indigo-500/20 transition-all duration-100 ease-out"
                            style={{ height: `${(manualTapCount / TARGET_MANUAL_TAPS) * 100}%` }}
                        />
                        <span className="text-5xl font-black text-white relative z-10">{manualTapCount}</span>
                        <span className="text-xs text-zinc-500 absolute bottom-8 font-bold tracking-widest z-10">/ {TARGET_MANUAL_TAPS}</span>
                    </div>

                    <div className="space-y-2 text-center">
                        <h3 className="text-xl font-bold text-white">Manual Override</h3>
                        <p className="text-zinc-400 text-sm">Camera unavailable. Tap rapidly to prove you are awake.</p>
                    </div>

                    <button 
                        onClick={handleManualCameraTap}
                        className="w-full py-4 bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl flex items-center justify-center gap-2 shadow-lg active:scale-95 transition-all"
                    >
                        <Hand className="w-5 h-5" />
                        Tap to Verify
                    </button>
                 </div>
             )}
          </div>
        )}

        {/* READING TASK UI */}
        {currentTask === TaskType.READ_SENTENCE && (
          <div className="space-y-8 text-center flex flex-col items-center">
             <div className="w-full p-8 bg-gradient-to-br from-indigo-900/20 to-zinc-900 rounded-2xl border border-indigo-500/20 shadow-[inset_0_0_20px_rgba(79,70,229,0.1)]">
                <p className="text-xl md:text-2xl font-serif italic text-indigo-300 leading-relaxed drop-shadow-sm">
                    "{sentence || "Loading challenge..."}"
                </p>
             </div>

             <div className="space-y-6 w-full flex flex-col items-center">
                 <p className="text-zinc-500 text-xs uppercase tracking-widest font-bold flex items-center gap-2">
                    {isRecording ? <span className="flex h-2 w-2 rounded-full bg-red-500 animate-ping"/> : null}
                    {isRecording ? "Recording Active..." : "Hold Button & Read Aloud"}
                 </p>

                 <button 
                    onMouseDown={startReading}
                    onMouseUp={stopReading}
                    onTouchStart={(e) => { e.preventDefault(); startReading(); }}
                    onTouchEnd={(e) => { e.preventDefault(); stopReading(); }}
                    onContextMenu={(e) => e.preventDefault()}
                    disabled={loading}
                    className={`
                        relative w-36 h-36 rounded-full flex items-center justify-center transition-all duration-200 select-none touch-none
                        ${isRecording 
                            ? 'bg-red-500 scale-110 shadow-[0_0_50px_rgba(239,68,68,0.5)] border-4 border-red-400' 
                            : 'bg-zinc-800 hover:bg-zinc-700 hover:scale-105 shadow-xl border-4 border-zinc-700'
                        }
                        ${loading ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer active:scale-95'}
                    `}
                 >
                    {isRecording && (
                        <div className="absolute inset-0 rounded-full border border-white/50 animate-ping duration-1000" />
                    )}

                    {loading ? (
                        <Loader2 className="animate-spin w-12 h-12 text-white/50" /> 
                    ) : (
                        <Mic className={`w-12 h-12 ${isRecording ? 'text-white' : 'text-zinc-400'} transition-colors`} />
                    )}
                 </button>

                 {isRecording ? (
                    <p className="text-red-400 text-sm animate-pulse font-medium">
                        Release button to verify
                    </p>
                 ) : (
                    <p className="text-zinc-600 text-sm">
                        Keep holding while you read the entire sentence.
                    </p>
                 )}
             </div>
          </div>
        )}

        {/* STEPS UI */}
        {currentTask === TaskType.WALK_STEPS && (
            <div className="space-y-6 text-center">
                <div className="w-40 h-40 mx-auto rounded-full border-8 border-zinc-800 flex items-center justify-center relative bg-zinc-950">
                    <span className="text-5xl font-black text-white">{steps}</span>
                    <span className="text-xs text-zinc-500 absolute bottom-8 font-bold tracking-widest">/ {targetSteps}</span>
                </div>
                <div className="space-y-2">
                    <h3 className="text-xl font-bold text-white">Get Moving!</h3>
                    <p className="text-zinc-400 text-sm">Walk around with your device. <br/><span className="text-xs text-zinc-600">(Or simulate by tapping below)</span></p>
                </div>
                <button 
                    onClick={incrementSteps}
                    className="w-full py-4 bg-zinc-800 hover:bg-zinc-700 text-white font-bold rounded-xl flex items-center justify-center gap-2 shadow-lg transition-transform active:scale-95"
                >
                    <Activity className="w-5 h-5" />
                    Simulate Step
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AlarmClock } from './components/AlarmClock';
import { TaskFlow } from './components/TaskFlow';
import { AlarmConfig, Persona, TaskType } from './types';
import { generateMotivationalQuote } from './services/geminiService';
import { Volume2, VolumeX } from 'lucide-react';

export default function App() {
  const [persona, setPersona] = useState<Persona>(Persona.STUDENT);
  const [config, setConfig] = useState<AlarmConfig>({
    time: "07:00",
    enabled: false,
    tasks: [TaskType.CHANTING, TaskType.PHOTO_FACE],
    snoozeAllowed: false
  });

  const [isAlarmRinging, setIsAlarmRinging] = useState(false);
  const [audioContext, setAudioContext] = useState<AudioContext | null>(null);
  const [oscillator, setOscillator] = useState<OscillatorNode | null>(null);
  const [quote, setQuote] = useState<string>("");

  // Wake Lock Logic
  useEffect(() => {
    let wakeLock: any = null;

    const requestWakeLock = async () => {
      if ('wakeLock' in navigator) {
        try {
          wakeLock = await (navigator as any).wakeLock.request('screen');
          console.log('Screen Wake Lock acquired');
        } catch (err: any) {
          console.error(`Wake Lock Error: ${err.name}, ${err.message}`);
        }
      }
    };

    const handleVisibilityChange = async () => {
      if (document.visibilityState === 'visible' && isAlarmRinging) {
        await requestWakeLock();
      }
    };

    if (isAlarmRinging) {
      requestWakeLock();
      document.addEventListener('visibilitychange', handleVisibilityChange);
    }

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      if (wakeLock) {
        wakeLock.release().then(() => {
            console.log('Screen Wake Lock released');
        }).catch((e: any) => console.error(e));
      }
    };
  }, [isAlarmRinging]);

  // Sound Logic
  const startAlarmSound = () => {
    try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(440, ctx.currentTime);
        // Annoying pulse
        osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);

        gain.gain.value = 0.1;

        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();

        setAudioContext(ctx);
        setOscillator(osc);

        // Pulse interval
        const interval = setInterval(() => {
            if(osc.frequency) {
               osc.frequency.setValueAtTime(440, ctx.currentTime); 
               osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);
            }
        }, 1000);
        (osc as any).interval = interval;

    } catch (e) {
        console.error("Audio error", e);
    }
  };

  const stopAlarmSound = () => {
    if (oscillator) {
        clearInterval((oscillator as any).interval);
        oscillator.stop();
        oscillator.disconnect();
    }
    if (audioContext) {
        audioContext.close();
    }
    setOscillator(null);
    setAudioContext(null);
  };

  const handleTriggerAlarm = async () => {
    setIsAlarmRinging(true);
    startAlarmSound();
    const q = await generateMotivationalQuote(persona);
    setQuote(q);
  };

  const handleTasksComplete = () => {
    setIsAlarmRinging(false);
    stopAlarmSound();
    setConfig(prev => ({ ...prev, enabled: false })); // Disable alarm after success
  };

