const StopwatchTab = () => {
    const [time, setTime] = useState(0);
    const [isRunning, setIsRunning] = useState(false);
    const [laps, setLaps] = useState<number[]>([]);
    const intervalRef = useRef<any>(null);

    useEffect(() => {
        if (isRunning) {
            intervalRef.current = setInterval(() => {
                setTime(prev => prev + 10);
            }, 10);
        } else {
            clearInterval(intervalRef.current);
        }
        return () => clearInterval(intervalRef.current);
    }, [isRunning]);

    const format = (ms: number) => {
        const min = Math.floor(ms / 60000);
        const sec = Math.floor((ms % 60000) / 1000);
        const cent = Math.floor((ms % 1000) / 10);
        return `${min.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}.${cent.toString().padStart(2, '0')}`;
    };

    const handleLap = () => {
        setLaps([time, ...laps]);
    };

    const handleReset = () => {
        setIsRunning(false);
        setTime(0);
        setLaps([]);
    };

    return (
        <div className="flex flex-col h-full pt-12 px-6">
            {/* Display */}
            <div className="flex justify-center py-12">
                <span className="text-6xl font-light font-mono text-white tracking-widest">
                    {format(time)}
                </span>
            </div>

            {/* Controls */}
            <div className="flex justify-between items-center mb-8 px-4">
                <button 
                    onClick={isRunning ? handleLap : handleReset}
                    className="w-20 h-20 rounded-full bg-zinc-800 border-2 border-zinc-700 flex items-center justify-center text-white font-medium active:bg-zinc-700"
                >
                    {isRunning ? "Lap" : "Reset"}
                </button>

                <div className="flex gap-2">
                    <div className="w-2 h-2 rounded-full bg-indigo-500/50" />
                    <div className="w-2 h-2 rounded-full bg-indigo-500/50" />
                </div>

                <button 
                    onClick={() => setIsRunning(!isRunning)}
                    className={`w-20 h-20 rounded-full border-2 flex items-center justify-center font-medium transition-colors ${
                        isRunning 
                        ? 'bg-red-900/30 border-red-900 text-red-500' 
                        : 'bg-green-900/30 border-green-900 text-green-500'
                    }`}
                >
                    {isRunning ? "Stop" : "Start"}
                </button>
            </div>

            {/* Laps */}
            <div className="flex-1 overflow-y-auto border-t border-zinc-800">
                {laps.map((lapTime, idx) => (
                    <div key={idx} className="flex justify-between py-4 border-b border-zinc-900 text-sm font-mono">
                        <span className="text-zinc-500">Lap {laps.length - idx}</span>
                        <span className="text-white">{format(lapTime)}</span>
                    </div>
                ))}
            </div>
        </div>
    );
};

