import React, { useState, useEffect, useRef } from 'react';
import { AlarmClock } from './components/AlarmClock';
import { TaskFlow } from './components/TaskFlow';
import { AlarmConfig, Persona, TaskType, Ringtone, DailyStats } from './types';
import { generateMotivationalQuote } from './services/geminiService';
import { Volume2, Database, Cpu } from 'lucide-react';

export default function App() {
  // --- DATABASE LAYER (Local Storage) ---
  const [persona, setPersona] = useState<Persona>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('wakeup_persona');
      return (saved as Persona) || Persona.STUDENT;
    }
    return Persona.STUDENT;
  });

  const [config, setConfig] = useState<AlarmConfig>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('wakeup_config');
      return saved ? JSON.parse(saved) : {
        time: "07:00",
        enabled: false,
        tasks: [TaskType.CHANTING, TaskType.PHOTO_FACE],
        snoozeAllowed: false,
        days: [1, 2, 3, 4, 5], // Mon-Fri default
        label: "Wake Up",
        ringtone: Ringtone.WAR,
        is24Hour: true // Default to 24h as requested
      };
    }
    return {
      time: "07:00",
      enabled: false,
      tasks: [TaskType.CHANTING, TaskType.PHOTO_FACE],
      snoozeAllowed: false,
      days: [1, 2, 3, 4, 5],
      label: "Wake Up",
      ringtone: Ringtone.WAR,
      is24Hour: true // Default to 24h as requested
    };
  });

  const [analytics, setAnalytics] = useState<DailyStats[]>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('wakeup_analytics');
      return saved ? JSON.parse(saved) : [];
    }
    return [];
  });

  useEffect(() => {
    localStorage.setItem('wakeup_persona', persona);
  }, [persona]);

  useEffect(() => {
    localStorage.setItem('wakeup_config', JSON.stringify(config));
  }, [config]);

  useEffect(() => {
    localStorage.setItem('wakeup_analytics', JSON.stringify(analytics));
  }, [analytics]);

  // --- APP LOGIC ---

  const [isAlarmRinging, setIsAlarmRinging] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const oscillatorRef = useRef<OscillatorNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const [quote, setQuote] = useState<string>("");

  // Analytics Tracking Refs
  const alarmStartTimeRef = useRef<number>(0);
  const sessionFailuresRef = useRef<number>(0);

  // Ensure AudioContext is unlocked on user interaction (browser autoplay policy)
  useEffect(() => {
    const unlockAudio = () => {
      if (audioContextRef.current && audioContextRef.current.state === 'suspended') {
        audioContextRef.current.resume().then(() => {
            console.log("AudioContext resumed by user gesture");
        });
      }
    };
    document.addEventListener('click', unlockAudio);
    document.addEventListener('touchstart', unlockAudio);
    return () => {
        document.removeEventListener('click', unlockAudio);
        document.removeEventListener('touchstart', unlockAudio);
    };
  }, []);

  // Wake Lock Logic
  useEffect(() => {
    let wakeLock: any = null;

    const requestWakeLock = async () => {
      if ('wakeLock' in navigator) {
        try {
          wakeLock = await (navigator as any).wakeLock.request('screen');
        } catch (err: any) {
          console.warn(`Wake Lock Request Failed: ${err.name}, ${err.message}`);
        }
      }
    };

    const handleVisibilityChange = async () => {
      if (document.visibilityState === 'visible' && isAlarmRinging) {
        await requestWakeLock();
      }
    };

    if (isAlarmRinging) {
      requestWakeLock();
      document.addEventListener('visibilitychange', handleVisibilityChange);
    }

    return () => {
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      if (wakeLock) {
        wakeLock.release().catch((e: any) => console.warn("Wake Lock release error", e));
      }
    };
  }, [isAlarmRinging]);

  // Sound Logic
  const startAlarmSound = () => {
    try {
        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
        const ctx = new AudioContextClass();
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();

        // Ringtone Logic
        if (config.ringtone === Ringtone.COSMIC) {
            osc.type = 'sine';
            osc.frequency.setValueAtTime(300, ctx.currentTime);
            osc.frequency.linearRampToValueAtTime(600, ctx.currentTime + 2);
            // Pulsing effect handled in interval
        } else if (config.ringtone === Ringtone.CLASSIC) {
            osc.type = 'square';
            osc.frequency.setValueAtTime(800, ctx.currentTime);
        } else {
            // WAR (Default)
            osc.type = 'sawtooth';
            osc.frequency.setValueAtTime(440, ctx.currentTime);
            osc.frequency.exponentialRampToValueAtTime(880, ctx.currentTime + 0.5);
        }

        gain.gain.value = 0.1;

        osc.connect(gain);
        gain.connect(ctx.destination);
        osc.start();

        audioContextRef.current = ctx;
        oscillatorRef.current = osc;
        gainNodeRef.current = gain;

        // Pattern Interval
        const interval = setInterval(() => {
            if(!osc.frequency) return;
            const t = ctx.currentTime;

            if (config.ringtone === Ringtone.COSMIC) {
                osc.frequency.setValueAtTime(300, t); 
                osc.frequency.linearRampToValueAtTime(600, t + 1.8);
            } else if (config.ringtone === Ringtone.CLASSIC) {
                // Beep Beep Beep
                gain.gain.setValueAtTime(0.1, t);
                gain.gain.setValueAtTime(0, t + 0.1);
                gain.gain.setValueAtTime(0.1, t + 0.2);
                gain.gain.setValueAtTime(0, t + 0.3);
            } else {
                // WAR
               osc.frequency.setValueAtTime(440, t); 
               osc.frequency.exponentialRampToValueAtTime(880, t + 0.5);
            }
        }, config.ringtone === Ringtone.CLASSIC ? 1000 : 2000);

        (osc as any).interval = interval;

    } catch (e) {
        console.error("Audio error", e);
    }
  };

  const stopAlarmSound = () => {
    if (oscillatorRef.current) {
        clearInterval((oscillatorRef.current as any).interval);
        try {
            oscillatorRef.current.stop();
            oscillatorRef.current.disconnect();
        } catch (e) { console.warn("Error stopping oscillator", e); }
    }
    if (audioContextRef.current) {
        try {
            audioContextRef.current.close();
        } catch (e) { console.warn("Error closing audio context", e); }
    }
    oscillatorRef.current = null;
    audioContextRef.current = null;
    gainNodeRef.current = null;
  };

  const muteAlarm = () => {
    if (gainNodeRef.current && audioContextRef.current) {
        try {
            gainNodeRef.current.gain.setTargetAtTime(0, audioContextRef.current.currentTime, 0.1);
        } catch(e) {}
    }
  };

  const unmuteAlarm = () => {
    if (gainNodeRef.current && audioContextRef.current) {
        try {
            gainNodeRef.current.gain.setTargetAtTime(0.1, audioContextRef.current.currentTime, 0.1);
        } catch(e) {}
    }
  };

  const handleTriggerAlarm = async () => {
    setIsAlarmRinging(true);
    // Analytics Reset
    alarmStartTimeRef.current = Date.now();
    sessionFailuresRef.current = 0;

    startAlarmSound();
    const q = await generateMotivationalQuote(persona);
    setQuote(q);
  };

  const handleTaskFail = () => {
    sessionFailuresRef.current += 1;
  };

  const handleTasksComplete = () => {
    setIsAlarmRinging(false);
    stopAlarmSound();

    // Save Analytics
    const durationSeconds = Math.round((Date.now() - alarmStartTimeRef.current) / 1000);
    const todayStr = new Date().toISOString().split('T')[0];

    const newStat: DailyStats = {
      date: todayStr,
      success: true,
      durationSeconds,
      failures: sessionFailuresRef.current,
      timestamp: Date.now()
    };

    setAnalytics(prev => [newStat, ...prev]); // Most recent first

    // If it's a one-time alarm (no repeat days), disable it
    if (config.days.length === 0) {
        setConfig({ ...config, enabled: false });
    }
    // If it repeats, keep it enabled for the next day
  };

  return (
    <div className="min-h-screen w-full bg-black text-zinc-100 flex flex-col relative overflow-hidden font-sans">
        {/* Background Gradients */}
        <div className="absolute top-[-20%] left-[-20%] w-[60%] h-[60%] bg-indigo-900/10 rounded-full blur-[120px] pointer-events-none" />
        <div className="absolute bottom-[-20%] right-[-20%] w-[60%] h-[60%] bg-rose-900/10 rounded-full blur-[120px] pointer-events-none" />

        {/* System Status Indicators */}
        {!isAlarmRinging && (
           <div className="absolute top-3 right-4 flex gap-2 z-20 opacity-40 hover:opacity-100 transition-opacity">
              <div className="flex items-center gap-1.5 px-2 py-1 bg-zinc-900 rounded border border-zinc-800 text-[9px] text-zinc-500 font-mono">
                  <Database className="w-2.5 h-2.5 text-emerald-500" />
                  <span>DB:OK</span>
              </div>
              <div className="flex items-center gap-1.5 px-2 py-1 bg-zinc-900 rounded border border-zinc-800 text-[9px] text-zinc-500 font-mono">
                  <Cpu className="w-2.5 h-2.5 text-indigo-500" />
                  <span>AI:OK</span>
              </div>
           </div>
        )}

        {isAlarmRinging ? (
            <div className="z-50 flex flex-col items-center justify-center min-h-screen relative bg-black">
                {/* Alarm Ringing Overlay */}
                <div className="absolute inset-0 bg-red-500/10 animate-pulse pointer-events-none"></div>

                <div className="relative z-10 flex flex-col items-center w-full">
                    <div className="mb-8 flex flex-col items-center animate-bounce">
                        <Volume2 className="w-12 h-12 text-red-500 mb-2" />
                        <h2 className="text-3xl font-black text-white tracking-widest uppercase">Wake Up</h2>
                        <p className="text-zinc-400 font-mono text-sm mt-1">{config.label}</p>
                    </div>

                    {/* Intro/Motivational Quote before tasks */}
                    <div className="mb-8 px-8 text-center max-w-lg">
                        <p className="text-lg font-bold text-white mb-2">Protocol: {persona}</p>
                        <p className="text-zinc-400 italic text-sm border-l-2 border-red-500 pl-4">"{quote}"</p>
                    </div>

                    <TaskFlow 
                        persona={persona}
                        tasks={config.tasks}
                        onComplete={handleTasksComplete}
                        onMuteAlarm={muteAlarm}
                        onUnmuteAlarm={unmuteAlarm}
                        onTaskFail={handleTaskFail}
                    />
                </div>
            </div>
        ) : (
            <AlarmClock 
                config={config}
                persona={persona}
                analytics={analytics}
                onUpdateConfig={setConfig}
                onUpdatePersona={setPersona}
                onTriggerAlarm={handleTriggerAlarm}
            />
        )}
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Persona, AlarmConfig, TaskType, Ringtone, DailyStats } from '../types';
import { 
    Bell, Play, Square, Moon, Briefcase, Dumbbell, GraduationCap, 
    User, BookOpen, Clock, Timer, Settings, Check, ChevronRight, 
    Music2, CalendarDays, Tag, Flag, BarChart3, TrendingUp, AlertTriangle, TimerReset
} from 'lucide-react';

interface AlarmClockProps {
  config: AlarmConfig;
  persona: Persona;
  analytics: DailyStats[];
  onUpdateConfig: (config: AlarmConfig) => void;
  onUpdatePersona: (persona: Persona) => void;
  onTriggerAlarm: () => void;
}

type Tab = 'CLOCK' | 'ALARM' | 'STOPWATCH' | 'STATS';

export const AlarmClock: React.FC<AlarmClockProps> = ({ config, persona, analytics, onUpdateConfig, onUpdatePersona, onTriggerAlarm }) => {
  const [activeTab, setActiveTab] = useState<Tab>('CLOCK');
  const [currentTime, setCurrentTime] = useState(new Date());

  // --- CLOCK TICKER ---
  useEffect(() => {
    const timer = setInterval(() => {
      const now = new Date();
      setCurrentTime(now);

      // ALARM TRIGGER LOGIC
      if (config.enabled) {
        const [alarmHour, alarmMinute] = config.time.split(':').map(Number);

        // Check seconds to trigger only once per minute
        if (now.getHours() === alarmHour && now.getMinutes() === alarmMinute && now.getSeconds() === 0) {

            // Check Days logic
            const today = now.getDay(); // 0 = Sun
            const days = config.days;

            // If days array is empty, it's a one-time alarm, so trigger it.
            // If days array has values, check if today is included.
            if (days.length === 0 || days.includes(today)) {
                onTriggerAlarm();
            }
        }
      }
    }, 1000);
    return () => clearInterval(timer);
  }, [config, onTriggerAlarm]);

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-black border-x border-zinc-900 shadow-2xl overflow-hidden relative">

        {/* TOP STATUS BAR (Fake) */}
        <div className="h-6 w-full flex justify-between items-center px-6 pt-2 z-20">
            <span className="text-[10px] font-medium text-white">
                {currentTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: !config.is24Hour })}
            </span>
            <div className="flex gap-1">
                <div className="w-3 h-3 bg-zinc-800 rounded-full" />
                <div className="w-3 h-3 bg-zinc-800 rounded-full" />
                <div className="w-4 h-2 bg-white rounded-[2px]" />
            </div>
        </div>

        {/* MAIN CONTENT AREA */}
        <div className="flex-1 overflow-y-auto scrollbar-hide pb-20">
            {activeTab === 'CLOCK' && <ClockTab currentTime={currentTime} config={config} persona={persona} onUpdatePersona={onUpdatePersona} />}
            {activeTab === 'ALARM' && <AlarmTab config={config} onUpdateConfig={onUpdateConfig} />}
            {activeTab === 'STOPWATCH' && <StopwatchTab />}
            {activeTab === 'STATS' && <StatsTab analytics={analytics} />}
        </div>

        {/* BOTTOM NAVIGATION DOCK */}
        <div className="absolute bottom-0 w-full h-20 bg-zinc-950/90 backdrop-blur-md border-t border-zinc-900 flex justify-around items-center pb-2 z-30">
            <NavIcon icon={<Clock className="w-6 h-6" />} label="Clock" isActive={activeTab === 'CLOCK'} onClick={() => setActiveTab('CLOCK')} />
            <NavIcon icon={<Bell className="w-6 h-6" />} label="Alarm" isActive={activeTab === 'ALARM'} onClick={() => setActiveTab('ALARM')} />
            <NavIcon icon={<Timer className="w-6 h-6" />} label="Stopwatch" isActive={activeTab === 'STOPWATCH'} onClick={() => setActiveTab('STOPWATCH')} />
            <NavIcon icon={<BarChart3 className="w-6 h-6" />} label="Stats" isActive={activeTab === 'STATS'} onClick={() => setActiveTab('STATS')} />
        </div>
    </div>
  );
};

// --- TAB COMPONENTS ---

const ClockTab = ({ currentTime, config, persona, onUpdatePersona }: any) => {
    // Determine greeting
    const hrs = currentTime.getHours();
    let greeting = "Good Morning";
    if (hrs >= 12) greeting = "Good Afternoon";
    if (hrs >= 17) greeting = "Good Evening";

    // Format Logic
    const hours = currentTime.getHours();
    const minutes = currentTime.getMinutes();
    const seconds = currentTime.getSeconds();

    // Convert to 12h if needed, otherwise keep 24h
    const displayHours = config.is24Hour ? hours : (hours % 12 || 12);
    const displayMinutes = minutes.toString().padStart(2, '0');
    const displayHoursStr = displayHours.toString().padStart(2, '0');
    const displaySecondsStr = seconds.toString().padStart(2, '0');

    const ampm = config.is24Hour ? '' : (hours >= 12 ? 'PM' : 'AM');

    const getPersonaIcon = (p: Persona) => {
        switch(p) {
            case Persona.STUDENT: return <BookOpen className="w-4 h-4" />;
            case Persona.CEO: return <Briefcase className="w-4 h-4" />;
            case Persona.GYM_FREAK: return <Dumbbell className="w-4 h-4" />;
            case Persona.SCHOOL_KID: return <GraduationCap className="w-4 h-4" />;
            case Persona.NIGHT_SHIFT_WORKER: return <Moon className="w-4 h-4" />;
            default: return <User className="w-4 h-4" />;
        }
    };

    return (
        <div className="flex flex-col items-center justify-center h-full px-6 space-y-12">

            <div className="text-center space-y-1">
                <span className="text-zinc-500 uppercase tracking-widest text-xs font-bold">{greeting}</span>
                <div className="flex items-baseline justify-center gap-2">
                    {/* Strict HH:MM format */}
                    <div className="text-7xl font-light text-white tracking-tighter tabular-nums flex items-center">
                        <span>{displayHoursStr}</span>
                        <span className="mx-1 animate-pulse text-zinc-600">:</span>
                        <span>{displayMinutes}</span>
                    </div>
                    {/* Seconds & AM/PM side by side */}
                    <div className="flex flex-col items-start justify-center text-sm font-bold text-zinc-600 pl-1">
                        <span>{displaySecondsStr}</span>
                        {ampm && <span>{ampm}</span>}
                    </div>
                </div>
                <p className="text-indigo-400 font-medium">
                    {currentTime.toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric'})}
                </p>
            </div>

            {/* Persona Quick Switch */}
            <div className="w-full">
                <div className="flex items-center justify-between mb-4">
                    <span className="text-xs font-bold text-zinc-600 uppercase tracking-wider">Current Identity</span>
                </div>
                <div className="grid grid-cols-2 gap-3">
                    {Object.values(Persona).map((p: any) => (
                        <button
                            key={p}
                            onClick={() => onUpdatePersona(p)}
                            className={`flex items-center gap-3 p-3 rounded-2xl border transition-all ${
                                persona === p 
                                ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg shadow-indigo-900/40' 
                                : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:bg-zinc-800'
                            }`}
                        >
                            <div className={`p-2 rounded-full ${persona === p ? 'bg-indigo-500' : 'bg-zinc-800'}`}>
                                {getPersonaIcon(p)}
                            </div>
                            <div className="flex flex-col items-start">
                                <span className="text-xs font-bold truncate max-w-[80px]">{p}</span>
                                {persona === p && <span className="text-[9px] opacity-70">Active</span>}
                            </div>
                        </button>
                    ))}
                </div>
            </div>

            <div className="w-full bg-zinc-900/50 rounded-2xl p-4 border border-zinc-800 flex items-center justify-between">
                <div className="flex gap-3 items-center">
                    <div className="bg-amber-500/10 p-2 rounded-full">
                        <Bell className="w-5 h-5 text-amber-500" />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-xs text-zinc-500 font-bold uppercase">Next Alarm</span>
                        <span className="text-white font-medium">
                            {config.enabled ? config.time : "No Alarm Set"}
                        </span>
                    </div>
                </div>
                <div className={`w-2 h-2 rounded-full ${config.enabled ? 'bg-green-500 shadow-[0_0_10px_rgba(34,197,94,0.5)]' : 'bg-zinc-700'}`} />
            </div>
        </div>
    );
};

const AlarmTab = ({ config, onUpdateConfig }: { config: AlarmConfig, onUpdateConfig: any }) => {

