            </div>
        </div>
    );
};

const StopwatchTab = () => {
    const [time, setTime] = useState(0);
    const [isRunning, setIsRunning] = useState(false);
    const [laps, setLaps] = useState<number[]>([]);
    const intervalRef = useRef<any>(null);

    useEffect(() => {
        if (isRunning) {
            intervalRef.current = setInterval(() => {
                setTime(prev => prev + 10);
            }, 10);
        } else {
            clearInterval(intervalRef.current);
        }
        return () => clearInterval(intervalRef.current);
    }, [isRunning]);

    const format = (ms: number) => {
        const min = Math.floor(ms / 60000);
        const sec = Math.floor((ms % 60000) / 1000);
        const cent = Math.floor((ms % 1000) / 10);
        return `${min.toString().padStart(2, '0')}:${sec.toString().padStart(2, '0')}.${cent.toString().padStart(2, '0')}`;
    };

    const handleLap = () => {
        setLaps([time, ...laps]);
    };

    const handleReset = () => {
        setIsRunning(false);
        setTime(0);
        setLaps([]);
    };

    return (
        <div className="flex flex-col h-full pt-12 px-6">
            {/* Display */}
            <div className="flex justify-center py-12">
                <span className="text-6xl font-light font-mono text-white tracking-widest">
                    {format(time)}
                </span>
            </div>

            {/* Controls */}
            <div className="flex justify-between items-center mb-8 px-4">
                <button 
                    onClick={isRunning ? handleLap : handleReset}
                    className="w-20 h-20 rounded-full bg-zinc-800 border-2 border-zinc-700 flex items-center justify-center text-white font-medium active:bg-zinc-700"
                >
                    {isRunning ? "Lap" : "Reset"}
                </button>

                <div className="flex gap-2">
                    <div className="w-2 h-2 rounded-full bg-indigo-500/50" />
                    <div className="w-2 h-2 rounded-full bg-indigo-500/50" />
                </div>

                <button 
                    onClick={() => setIsRunning(!isRunning)}
                    className={`w-20 h-20 rounded-full border-2 flex items-center justify-center font-medium transition-colors ${
                        isRunning 
                        ? 'bg-red-900/30 border-red-900 text-red-500' 
                        : 'bg-green-900/30 border-green-900 text-green-500'
                    }`}
                >
                    {isRunning ? "Stop" : "Start"}
                </button>
            </div>

            {/* Laps */}
            <div className="flex-1 overflow-y-auto border-t border-zinc-800">
                {laps.map((lapTime, idx) => (
                    <div key={idx} className="flex justify-between py-4 border-b border-zinc-900 text-sm font-mono">
                        <span className="text-zinc-500">Lap {laps.length - idx}</span>
                        <span className="text-white">{format(lapTime)}</span>
                    </div>
                ))}
            </div>
        </div>
    );
};

const StatsTab = ({ analytics }: { analytics: DailyStats[] }) => {
    // Computed metrics
    const todayStr = new Date().toISOString().split('T')[0];
    const todaysStats = analytics.find(a => a.date === todayStr);

    // Average Time (last 7 entries)
    const recent = analytics.slice(0, 7);
    const avgTime = recent.length > 0 
        ? Math.round(recent.reduce((acc, curr) => acc + curr.durationSeconds, 0) / recent.length)
        : 0;

    // Success Rate (last 7 entries) - Note: currently logic treats every entry as success since we only log on completion, 
    // but in a real app we might log missed alarms too. For now we consider 'failures' as the negative metric.

    // Total failures today
    const failuresToday = todaysStats ? todaysStats.failures : 0;

    return (
        <div className="px-5 py-8 space-y-8">
            <h2 className="text-3xl font-bold text-white mb-6">Analytics</h2>

            <div className="grid grid-cols-2 gap-4">
                {/* Card 1: Success Rate (Dummy Calculation for visual) */}
                <div className="bg-zinc-900 rounded-2xl p-5 border border-zinc-800 flex flex-col justify-between h-32 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <TrendingUp className="w-12 h-12 text-emerald-500" />
                    </div>
                    <span className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Success Rate</span>
                    <div>
                        <span className="text-4xl font-black text-emerald-500">100%</span>
                        <p className="text-[10px] text-zinc-500 mt-1">Last 7 Days</p>
                    </div>
                </div>

                {/* Card 2: Today's Failures */}
                <div className="bg-zinc-900 rounded-2xl p-5 border border-zinc-800 flex flex-col justify-between h-32 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <AlertTriangle className="w-12 h-12 text-rose-500" />
                    </div>
                    <span className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Today's Fails</span>
                    <div>
                        <span className={`text-4xl font-black ${failuresToday > 0 ? 'text-rose-500' : 'text-white'}`}>{failuresToday}</span>
                        <p className="text-[10px] text-zinc-500 mt-1">Verification Errors</p>
                    </div>
                </div>

                {/* Card 3: Avg Time */}
                <div className="col-span-2 bg-zinc-900 rounded-2xl p-5 border border-zinc-800 flex flex-col justify-between h-32 relative overflow-hidden group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                         <TimerReset className="w-12 h-12 text-indigo-500" />
                    </div>
                    <span className="text-zinc-500 text-xs font-bold uppercase tracking-wider">Avg Reaction Time</span>
                    <div className="flex items-end gap-2">
                        <span className="text-5xl font-black text-indigo-400">{avgTime}</span>
                        <span className="text-lg text-zinc-500 font-bold mb-2">seconds</span>
                    </div>
                </div>
            </div>

            {/* History List */}
            <div className="space-y-4">
                <h3 className="text-sm font-bold text-zinc-500 uppercase tracking-widest">History</h3>
                {analytics.length === 0 ? (
                    <div className="p-8 text-center border border-dashed border-zinc-800 rounded-xl">
                        <p className="text-zinc-600 text-sm">No data recorded yet.</p>
                    </div>
                ) : (
                    analytics.map((stat, idx) => (
                        <div key={idx} className="bg-zinc-900/50 p-4 rounded-xl border border-zinc-800 flex items-center justify-between">
                            <div className="flex flex-col">
                                <span className="text-white font-bold text-sm">
                                    {new Date(stat.date).toLocaleDateString(undefined, {weekday: 'short', month: 'short', day: 'numeric'})}
                                </span>
                                <span className="text-xs text-zinc-500">
                                    {stat.failures === 0 ? 'Perfect Run' : `${stat.failures} attempts failed`}
                                </span>
                            </div>
                            <div className="flex items-center gap-3">
                                <div className="text-right">
                                    <span className="block text-indigo-400 font-mono font-bold">{stat.durationSeconds}s</span>
                                    <span className="text-[10px] text-zinc-600">DURATION</span>
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

const NavIcon = ({ icon, label, isActive, onClick }: any) => (
    <button onClick={onClick} className={`flex flex-col items-center gap-1 w-20 ${isActive ? 'text-indigo-500' : 'text-zinc-600'}`}>
